import pygame
import random
import time

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = (GRID_WIDTH * 3 + 6) * BLOCK_SIZE  # Three grids + spacing
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)

COLORS = [RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA, ORANGE]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]],  # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color

    def get_x(self):
        return self.x

    def get_y(self):
        return self.y

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

class Grid:
    def __init__(self, width, height, offset_x):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]
        self.offset_x = offset_x

    def is_valid_move(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    grid_x = x + j
                    grid_y = y + i
                    if (grid_x < 0 or grid_x >= self.width or grid_y >= self.height or
                            (grid_y >= 0 and self.grid[grid_y][grid_x] != 0)):
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        color = tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen):
        for i in range(self.height):
            for j in range(self.width):
                if self.grid[i][j]:
                    pygame.draw.rect(screen, self.grid[i][j],
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK,
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(screen, WHITE,
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def is_game_over(self):
        return any(self.grid[0])

class Player:
    def __init__(self, player_id, grid):
        self.player_id = player_id
        self.grid = grid
        self.score = 0
        self.lines_cleared = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.choice(COLORS)
        return Tetromino(self.grid.width // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(self.current_tetromino):
            return False  # Game over
        return True

    def move_tetromino(self, dx):
        self.current_tetromino.move(dx, 0)
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.move(-dx, 0)

    def drop_tetromino(self):
        self.current_tetromino.move(0, 1)
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.move(0, -1)
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.lines_cleared += lines_cleared
            self.score += lines_cleared * lines_cleared * 100  # Example scoring
            self.current_tetromino = None
            return True  # Tetromino landed
        return False

    def rotate_tetromino(self):
        original_shape = [row[:] for row in self.current_tetromino.shape] # Deep copy
        self.current_tetromino.rotate()
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.shape = original_shape # Revert rotation

    def get_score(self):
        return self.score

    def get_lines_cleared(self):
        return self.lines_cleared

    def draw_next_tetromino(self, screen, x, y):
        shape = self.next_tetromino.get_shape()
        color = self.next_tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, color, (x + j * BLOCK_SIZE, y + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK, (x + j * BLOCK_SIZE, y + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Tetris Collaboration")
    clock = pygame.time.Clock()

    # Initialize grids and players
    grid1 = Grid(GRID_WIDTH, GRID_HEIGHT, 0)
    grid2 = Grid(GRID_WIDTH, GRID_HEIGHT, (GRID_WIDTH + 2) * BLOCK_SIZE)
    grid3 = Grid(GRID_WIDTH, GRID_HEIGHT, (GRID_WIDTH * 2 + 4) * BLOCK_SIZE)

    player1 = Player(1, grid1)
    player2 = Player(2, grid2)
    player3 = Player(3, grid3)

    players = [player1, player2, player3]
    game_over = [False, False, False]

    # Spawn initial tetrominoes
    for player in players:
        if not player.spawn_tetromino():
            game_over[player.player_id - 1] = True

    drop_timer = 0
    drop_interval = 500  # Milliseconds

    running = True
    while running:
        clock.tick(FPS)
        screen.fill(BLACK)

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT and not game_over[0]:
                    player1.move_tetromino(-1)
                if event.key == pygame.K_RIGHT and not game_over[0]:
                    player1.move_tetromino(1)
                if event.key == pygame.K_UP and not game_over[0]:
                    player1.rotate_tetromino()
                if event.key == pygame.K_a and not game_over[1]:
                    player2.move_tetromino(-1)
                if event.key == pygame.K_d and not game_over[1]:
                    player2.move_tetromino(1)
                if event.key == pygame.K_w and not game_over[1]:
                    player2.rotate_tetromino()
                if event.key == pygame.K_j and not game_over[2]:
                    player3.move_tetromino(-1)
                if event.key == pygame.K_l and not game_over[2]:
                    player3.move_tetromino(1)
                if event.key == pygame.K_i and not game_over[2]:
                    player3.rotate_tetromino()

        drop_timer += clock.get_rawtime()

        for i, player in enumerate(players):
            if not game_over[i]:
                if drop_timer >= drop_interval:
                    if player.current_tetromino:
                        landed = player.drop_tetromino()
                        if landed:
                            if not player.spawn_tetromino():
                                game_over[i] = True
                    else:
                        if not player.spawn_tetromino():
                            game_over[i] = True

        if drop_timer >= drop_interval:
            drop_timer = 0

        # Draw everything
        grid1.draw(screen)
        grid2.draw(screen)
        grid3.draw(screen)

        for i, player in enumerate(players):
            if player.current_tetromino:
                shape = player.current_tetromino.get_shape()
                color = player.current_tetromino.get_color()
                x = player.current_tetromino.get_x()
                y = player.current_tetromino.get_y()
                offset_x = player.grid.offset_x
                for row_index, row in enumerate(shape):
                    for col_index, cell in enumerate(row):
                        if cell:
                            pygame.draw.rect(screen, color, (offset_x + (x + col_index) * BLOCK_SIZE, (y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                            pygame.draw.rect(screen, BLACK, (offset_x + (x + col_index) * BLOCK_SIZE, (y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

            player.draw_next_tetromino(screen, player.grid.offset_x + GRID_WIDTH * BLOCK_SIZE + 10, 10)

            font = pygame.font.Font(None, 30)
            score_text = font.render(f"Player {player.player_id} Score: {player.get_score()}", True, WHITE)
            screen.blit(score_text, (player.grid.offset_x, HEIGHT - 30))

        # Check if all players have lost
        if all(game_over):
            font = pygame.font.Font(None, 50)
            game_over_text = font.render("Game Over!", True, RED)
            text_rect = game_over_text.get_rect(center=(WIDTH // 2, HEIGHT // 2))
            screen.blit(game_over_text, text_rect)

            # Calculate overall score and contribution
            total_score = sum(player.get_score() for player in players)
            if total_score > 0:
                contributions = [player.get_score() / total_score for player in players]
            else:
                contributions = [1/len(players)] * len(players) # Equal contribution if no score

            contribution_texts = []
            for i, player in enumerate(players):
                contribution_text = font.render(f"Player {player.player_id} Contribution: {contributions[i]:.2f}", True, WHITE)
                contribution_texts.append(contribution_text)
                screen.blit(contribution_text, (WIDTH // 2 - contribution_text.get_width() // 2, HEIGHT // 2 + 50 + i * 30))

        pygame.display.flip()

    pygame.quit()

if __name__ == "__main__":
    main()

import pygame
import random
import time

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = (GRID_WIDTH * 3 + 6) * BLOCK_SIZE  # Three grids + spacing
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
COLORS = [
    (0, 0, 0),       # Black (empty)
    (0, 255, 255),   # Cyan (I)
    (0, 0, 255),     # Blue (J)
    (255, 127, 0),   # Orange (L)
    (255, 255, 0),   # Yellow (O)
    (0, 255, 0),     # Green (S)
    (255, 0, 0),     # Red (Z)
    (128, 0, 128)    # Purple (T)
]

SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]

class TetrisGrid:
    def __init__(self, x_offset):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.x_offset = x_offset
        self.score = 0
        self.lines_cleared = 0
        self.game_over = False
        self.current_piece = None
        self.current_x = 0
        self.current_y = 0
        self.next_piece = self.new_piece()

    def new_piece(self):
        shape_index = random.randint(0, len(SHAPES) - 1)
        return (SHAPES[shape_index], shape_index + 1)  # Return shape and color index

    def spawn_piece(self):
        self.current_piece = self.next_piece
        self.next_piece = self.new_piece()
        self.current_x = GRID_WIDTH // 2 - len(self.current_piece[0][0]) // 2
        self.current_y = 0
        if not self.is_valid_position(self.current_piece[0], self.current_x, self.current_y):
            self.game_over = True

    def rotate(self):
        if self.current_piece is None:
            return
        rotated_piece = list(zip(*self.current_piece[0][::-1]))
        if self.is_valid_position(rotated_piece, self.current_x, self.current_y):
            self.current_piece = (rotated_piece, self.current_piece[1])

    def move(self, dx):
        if self.current_piece is None:
            return
        new_x = self.current_x + dx
        if self.is_valid_position(self.current_piece[0], new_x, self.current_y):
            self.current_x = new_x

    def drop(self):
        if self.current_piece is None:
            return
        new_y = self.current_y + 1
        if self.is_valid_position(self.current_piece[0], self.current_x, new_y):
            self.current_y = new_y
        else:
            self.lock_piece()

    def is_valid_position(self, piece, x, y):
        for row_index, row in enumerate(piece):
            for col_index, cell in enumerate(row):
                if cell:
                    grid_x = x + col_index
                    grid_y = y + row_index
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT:
                        return False
                    if grid_y >= 0 and self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def lock_piece(self):
        for row_index, row in enumerate(self.current_piece[0]):
            for col_index, cell in enumerate(row):
                if cell:
                    self.grid[self.current_y + row_index][self.current_x + col_index] = self.current_piece[1]
        self.clear_lines()
        self.spawn_piece()

    def clear_lines(self):
        lines_cleared = 0
        new_grid = []
        for row in self.grid:
            if all(cell != 0 for cell in row):
                lines_cleared += 1
            else:
                new_grid.append(row)

        for _ in range(lines_cleared):
            new_grid.insert(0, [0] * GRID_WIDTH)

        self.grid = new_grid
        self.lines_cleared += lines_cleared
        if lines_cleared == 1:
            self.score += 40
        elif lines_cleared == 2:
            self.score += 100
        elif lines_cleared == 3:
            self.score += 300
        elif lines_cleared == 4:
            self.score += 1200

    def draw(self, screen):
        # Draw Grid
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = COLORS[self.grid[y][x]]
                pygame.draw.rect(screen, color, (self.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, (50, 50, 50), (self.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

        # Draw Current Piece
        if self.current_piece:
            for row_index, row in enumerate(self.current_piece[0]):
                for col_index, cell in enumerate(row):
                    if cell:
                        color = COLORS[self.current_piece[1]]
                        pygame.draw.rect(screen, color, (self.x_offset + (self.current_x + col_index) * BLOCK_SIZE, (self.current_y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                        pygame.draw.rect(screen, (50, 50, 50), (self.x_offset + (self.current_x + col_index) * BLOCK_SIZE, (self.current_y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

        # Draw Next Piece Preview
        font = pygame.font.Font(None, 30)
        text = font.render("Next:", True, (255, 255, 255))
        screen.blit(text, (self.x_offset, HEIGHT + 10))

        next_piece_shape = self.next_piece[0]
        next_piece_color = COLORS[self.next_piece[1]]
        for row_index, row in enumerate(next_piece_shape):
            for col_index, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, next_piece_color, (self.x_offset + col_index * BLOCK_SIZE, HEIGHT + 40 + row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, (50, 50, 50), (self.x_offset + col_index * BLOCK_SIZE, HEIGHT + 40 + row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

        # Draw Score
        score_text = font.render(f"Score: {self.score}", True, (255, 255, 255))
        screen.blit(score_text, (self.x_offset, HEIGHT + 150))

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT + 200))
        pygame.display.set_caption("Tetris WHO Collaboration")
        self.clock = pygame.time.Clock()
        self.grids = [
            TetrisGrid(0),
            TetrisGrid(GRID_WIDTH * BLOCK_SIZE + BLOCK_SIZE * 2),
            TetrisGrid((GRID_WIDTH * 2 + 4) * BLOCK_SIZE)
        ]
        self.font = pygame.font.Font(None, 36)
        self.game_over = False
        self.total_score = 0
        self.player_contributions = [0, 0, 0]
        self.start_time = time.time()
        self.game_duration = 60  # Game duration in seconds

        for grid in self.grids:
            grid.spawn_piece()

    def handle_input(self, event, player_index):
        grid = self.grids[player_index]
        if grid.game_over:
            return

        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT:
                grid.move(-1)
            if event.key == pygame.K_RIGHT:
                grid.move(1)
            if event.key == pygame.K_DOWN:
                grid.drop()
            if event.key == pygame.K_UP:
                grid.rotate()
            if event.key == pygame.K_SPACE:
                while not grid.game_over:
                    grid.drop()
                    if not grid.is_valid_position(grid.current_piece[0], grid.current_x, grid.current_y + 1):
                        grid.lock_piece()
                        break

    def update(self):
        if self.game_over:
            return

        for i, grid in enumerate(self.grids):
            if not grid.game_over:
                grid.drop()
                if grid.game_over:
                    print(f"Player {i+1} Game Over!")
                    self.calculate_contributions()
                    if all(g.game_over for g in self.grids):
                        self.game_over = True
                        print("All players game over!")

        self.clock.tick(FPS)

    def calculate_contributions(self):
        total_lines_cleared = sum(grid.lines_cleared for grid in self.grids)
        if total_lines_cleared == 0:
            self.player_contributions = [1/3, 1/3, 1/3]
            return

        self.player_contributions = [grid.lines_cleared / total_lines_cleared for grid in self.grids]
        self.total_score = sum(grid.score for grid in self.grids)

    def draw(self):
        self.screen.fill((0, 0, 0))

        for grid in self.grids:
            grid.draw(self.screen)

        # Display Player Contributions
        for i, contribution in enumerate(self.player_contributions):
            text = self.font.render(f"Player {i+1} Contribution: {contribution:.2f}", True, (255, 255, 255))
            self.screen.blit(text, (10, HEIGHT + 10 + i * 30))

        # Display Total Score
        total_score_text = self.font.render(f"Total Score: {self.total_score}", True, (255, 255, 255))
        self.screen.blit(total_score_text, (10, HEIGHT + 100))

        # Display Game Over Message
        if self.game_over:
            game_over_text = self.font.render("Game Over! Press any key to exit.", True, (255, 0, 0))
            self.screen.blit(game_over_text, (WIDTH // 2 - game_over_text.get_width() // 2, HEIGHT // 2))

        pygame.display.flip()

    def run(self):
        running = True
        player_controls = [
            (pygame.K_LEFT, pygame.K_RIGHT, pygame.K_DOWN, pygame.K_UP, pygame.K_SPACE),  # Player 1
            (pygame.K_a, pygame.K_d, pygame.K_s, pygame.K_w, pygame.K_q),  # Player 2
            (pygame.K_j, pygame.K_l, pygame.K_k, pygame.K_i, pygame.K_u)   # Player 3
        ]

        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                for i in range(3):
                    self.handle_input(event, i)

            self.update()
            self.draw()

            if self.game_over:
                waiting = True
                while waiting:
                    for event in pygame.event.get():
                        if event.type == pygame.QUIT:
                            running = False
                            waiting = False
                        if event.type == pygame.KEYDOWN:
                            running = False
                            waiting = False

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

import pygame
import random
import time

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = (GRID_WIDTH * 3 + 6) * BLOCK_SIZE  # Three grids + spacing
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)

COLORS = [RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA, ORANGE]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]],  # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color

    def get_x(self):
        return self.x

    def get_y(self):
        return self.y

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

class Grid:
    def __init__(self, width, height, offset_x):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]
        self.offset_x = offset_x

    def is_valid_move(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    grid_x = x + j
                    grid_y = y + i
                    if (grid_x < 0 or grid_x >= self.width or grid_y >= self.height or
                            (grid_y >= 0 and self.grid[grid_y][grid_x] != 0)):
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        color = tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen):
        for i in range(self.height):
            for j in range(self.width):
                if self.grid[i][j]:
                    pygame.draw.rect(screen, self.grid[i][j],
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK,
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(screen, WHITE,
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def is_game_over(self):
        return any(self.grid[0])

class Player:
    def __init__(self, player_id, grid):
        self.player_id = player_id
        self.grid = grid
        self.score = 0
        self.lines_cleared = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.choice(COLORS)
        return Tetromino(self.grid.width // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(self.current_tetromino):
            return False  # Game over
        return True

    def move_tetromino(self, dx):
        self.current_tetromino.move(dx, 0)
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.move(-dx, 0)

    def drop_tetromino(self):
        self.current_tetromino.move(0, 1)
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.move(0, -1)
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.lines_cleared += lines_cleared
            self.score += lines_cleared * lines_cleared * 100  # Example scoring
            self.current_tetromino = None
            return True  # Tetromino landed
        return False

    def rotate_tetromino(self):
        original_shape = [row[:] for row in self.current_tetromino.shape] # Deep copy
        self.current_tetromino.rotate()
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.shape = original_shape # Revert rotation

    def get_score(self):
        return self.score

    def get_lines_cleared(self):
        return self.lines_cleared

    def draw_next_tetromino(self, screen, x, y):
        shape = self.next_tetromino.get_shape()
        color = self.next_tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, color, (x + j * BLOCK_SIZE, y + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK, (x + j * BLOCK_SIZE, y + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Tetris Collaboration")
    clock = pygame.time.Clock()

    # Initialize grids and players
    grid1 = Grid(GRID_WIDTH, GRID_HEIGHT, 0)
    grid2 = Grid(GRID_WIDTH, GRID_HEIGHT, (GRID_WIDTH + 2) * BLOCK_SIZE)
    grid3 = Grid(GRID_WIDTH, GRID_HEIGHT, (GRID_WIDTH * 2 + 4) * BLOCK_SIZE)

    player1 = Player(1, grid1)
    player2 = Player(2, grid2)
    player3 = Player(3, grid3)

    players = [player1, player2, player3]
    game_over = [False, False, False]

    # Spawn initial tetrominoes
    for player in players:
        if not player.spawn_tetromino():
            game_over[player.player_id - 1] = True

    drop_timer = 0
    drop_interval = 500  # Milliseconds

    running = True
    while running:
        clock.tick(FPS)
        screen.fill(BLACK)

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT and not game_over[0]:
                    player1.move_tetromino(-1)
                if event.key == pygame.K_RIGHT and not game_over[0]:
                    player1.move_tetromino(1)
                if event.key == pygame.K_UP and not game_over[0]:
                    player1.rotate_tetromino()
                if event.key == pygame.K_a and not game_over[1]:
                    player2.move_tetromino(-1)
                if event.key == pygame.K_d and not game_over[1]:
                    player2.move_tetromino(1)
                if event.key == pygame.K_w and not game_over[1]:
                    player2.rotate_tetromino()
                if event.key == pygame.K_j and not game_over[2]:
                    player3.move_tetromino(-1)
                if event.key == pygame.K_l and not game_over[2]:
                    player3.move_tetromino(1)
                if event.key == pygame.K_i and not game_over[2]:
                    player3.rotate_tetromino()

        drop_timer += clock.get_rawtime()

        for i, player in enumerate(players):
            if not game_over[i]:
                if drop_timer >= drop_interval:
                    if player.current_tetromino:
                        landed = player.drop_tetromino()
                        if landed:
                            if not player.spawn_tetromino():
                                game_over[i] = True
                    else:
                        if not player.spawn_tetromino():
                            game_over[i] = True

        if drop_timer >= drop_interval:
            drop_timer = 0

        # Draw everything
        grid1.draw(screen)
        grid2.draw(screen)
        grid3.draw(screen)

        for i, player in enumerate(players):
            if player.current_tetromino:
                shape = player.current_tetromino.get_shape()
                color = player.current_tetromino.get_color()
                x = player.current_tetromino.get_x()
                y = player.current_tetromino.get_y()
                offset_x = player.grid.offset_x
                for row_index, row in enumerate(shape):
                    for col_index, cell in enumerate(row):
                        if cell:
                            pygame.draw.rect(screen, color, (offset_x + (x + col_index) * BLOCK_SIZE, (y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                            pygame.draw.rect(screen, BLACK, (offset_x + (x + col_index) * BLOCK_SIZE, (y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

            player.draw_next_tetromino(screen, player.grid.offset_x + GRID_WIDTH * BLOCK_SIZE + 10, 10)

            font = pygame.font.Font(None, 30)
            score_text = font.render(f"Player {player.player_id} Score: {player.get_score()}", True, WHITE)
            screen.blit(score_text, (player.grid.offset_x, HEIGHT - 30))

        # Check if all players have lost
        if all(game_over):
            font = pygame.font.Font(None, 50)
            game_over_text = font.render("Game Over!", True, RED)
            text_rect = game_over_text.get_rect(center=(WIDTH // 2, HEIGHT // 2))
            screen.blit(game_over_text, text_rect)

            # Calculate overall score and contribution
            total_score = sum(player.get_score() for player in players)
            if total_score > 0:
                contributions = [player.get_score() / total_score for player in players]
            else:
                contributions = [1/len(players)] * len(players) # Equal contribution if no score

            contribution_texts = []
            for i, player in enumerate(players):
                contribution_text = font.render(f"Player {player.player_id} Contribution: {contributions[i]:.2f}", True, WHITE)
                contribution_texts.append(contribution_text)
                screen.blit(contribution_text, (WIDTH // 2 - contribution_text.get_width() // 2, HEIGHT // 2 + 50 + i * 30))

        pygame.display.flip()

    pygame.quit()

if __name__ == "__main__":
    main()

import pygame
import random
import time

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = (GRID_WIDTH * 3 + 6) * BLOCK_SIZE  # Three grids + spacing
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
COLORS = [
    (0, 0, 0),       # Black (empty)
    (0, 255, 255),   # Cyan (I)
    (0, 0, 255),     # Blue (J)
    (255, 127, 0),   # Orange (L)
    (255, 255, 0),   # Yellow (O)
    (0, 255, 0),     # Green (S)
    (255, 0, 0),     # Red (Z)
    (128, 0, 128)    # Purple (T)
]

SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]

class TetrisGrid:
    def __init__(self, x_offset):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.x_offset = x_offset
        self.score = 0
        self.lines_cleared = 0
        self.game_over = False
        self.current_piece = None
        self.current_x = 0
        self.current_y = 0
        self.next_piece = self.new_piece()

    def new_piece(self):
        shape_index = random.randint(0, len(SHAPES) - 1)
        return (SHAPES[shape_index], shape_index + 1)  # Return shape and color index

    def spawn_piece(self):
        self.current_piece = self.next_piece
        self.next_piece = self.new_piece()
        self.current_x = GRID_WIDTH // 2 - len(self.current_piece[0][0]) // 2
        self.current_y = 0
        if not self.is_valid_position(self.current_piece[0], self.current_x, self.current_y):
            self.game_over = True

    def rotate(self):
        if self.current_piece is None:
            return
        rotated_piece = list(zip(*self.current_piece[0][::-1]))
        if self.is_valid_position(rotated_piece, self.current_x, self.current_y):
            self.current_piece = (rotated_piece, self.current_piece[1])

    def move(self, dx):
        if self.current_piece is None:
            return
        new_x = self.current_x + dx
        if self.is_valid_position(self.current_piece[0], new_x, self.current_y):
            self.current_x = new_x

    def drop(self):
        if self.current_piece is None:
            return
        new_y = self.current_y + 1
        if self.is_valid_position(self.current_piece[0], self.current_x, new_y):
            self.current_y = new_y
        else:
            self.lock_piece()

    def is_valid_position(self, piece, x, y):
        for row_index, row in enumerate(piece):
            for col_index, cell in enumerate(row):
                if cell:
                    grid_x = x + col_index
                    grid_y = y + row_index
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT:
                        return False
                    if grid_y >= 0 and self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def lock_piece(self):
        for row_index, row in enumerate(self.current_piece[0]):
            for col_index, cell in enumerate(row):
                if cell:
                    self.grid[self.current_y + row_index][self.current_x + col_index] = self.current_piece[1]
        self.clear_lines()
        self.spawn_piece()

    def clear_lines(self):
        lines_cleared = 0
        new_grid = []
        for row in self.grid:
            if all(cell != 0 for cell in row):
                lines_cleared += 1
            else:
                new_grid.append(row)

        for _ in range(lines_cleared):
            new_grid.insert(0, [0] * GRID_WIDTH)

        self.grid = new_grid
        self.lines_cleared += lines_cleared
        if lines_cleared == 1:
            self.score += 40
        elif lines_cleared == 2:
            self.score += 100
        elif lines_cleared == 3:
            self.score += 300
        elif lines_cleared == 4:
            self.score += 1200

    def draw(self, screen):
        # Draw Grid
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = COLORS[self.grid[y][x]]
                pygame.draw.rect(screen, color, (self.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, (50, 50, 50), (self.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

        # Draw Current Piece
        if self.current_piece:
            for row_index, row in enumerate(self.current_piece[0]):
                for col_index, cell in enumerate(row):
                    if cell:
                        color = COLORS[self.current_piece[1]]
                        pygame.draw.rect(screen, color, (self.x_offset + (self.current_x + col_index) * BLOCK_SIZE, (self.current_y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                        pygame.draw.rect(screen, (50, 50, 50), (self.x_offset + (self.current_x + col_index) * BLOCK_SIZE, (self.current_y + row_index) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

        # Draw Next Piece Preview
        font = pygame.font.Font(None, 30)
        text = font.render("Next:", True, (255, 255, 255))
        screen.blit(text, (self.x_offset, HEIGHT + 10))

        next_piece_shape = self.next_piece[0]
        next_piece_color = COLORS[self.next_piece[1]]
        for row_index, row in enumerate(next_piece_shape):
            for col_index, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, next_piece_color, (self.x_offset + col_index * BLOCK_SIZE, HEIGHT + 40 + row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, (50, 50, 50), (self.x_offset + col_index * BLOCK_SIZE, HEIGHT + 40 + row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

        # Draw Score
        score_text = font.render(f"Score: {self.score}", True, (255, 255, 255))
        screen.blit(score_text, (self.x_offset, HEIGHT + 150))

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT + 200))
        pygame.display.set_caption("Tetris WHO Collaboration")
        self.clock = pygame.time.Clock()
        self.grids = [
            TetrisGrid(0),
            TetrisGrid(GRID_WIDTH * BLOCK_SIZE + BLOCK_SIZE * 2),
            TetrisGrid((GRID_WIDTH * 2 + 4) * BLOCK_SIZE)
        ]
        self.font = pygame.font.Font(None, 36)
        self.game_over = False
        self.total_score = 0
        self.player_contributions = [0, 0, 0]
        self.start_time = time.time()
        self.game_duration = 60  # Game duration in seconds

        for grid in self.grids:
            grid.spawn_piece()

    def handle_input(self, event, player_index):
        grid = self.grids[player_index]
        if grid.game_over:
            return

        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT:
                grid.move(-1)
            if event.key == pygame.K_RIGHT:
                grid.move(1)
            if event.key == pygame.K_DOWN:
                grid.drop()
            if event.key == pygame.K_UP:
                grid.rotate()
            if event.key == pygame.K_SPACE:
                while not grid.game_over:
                    grid.drop()
                    if not grid.is_valid_position(grid.current_piece[0], grid.current_x, grid.current_y + 1):
                        grid.lock_piece()
                        break

    def update(self):
        if self.game_over:
            return

        for i, grid in enumerate(self.grids):
            if not grid.game_over:
                grid.drop()
                if grid.game_over:
                    print(f"Player {i+1} Game Over!")
                    self.calculate_contributions()
                    if all(g.game_over for g in self.grids):
                        self.game_over = True
                        print("All players game over!")

        self.clock.tick(FPS)

    def calculate_contributions(self):
        total_lines_cleared = sum(grid.lines_cleared for grid in self.grids)
        if total_lines_cleared == 0:
            self.player_contributions = [1/3, 1/3, 1/3]
            return

        self.player_contributions = [grid.lines_cleared / total_lines_cleared for grid in self.grids]
        self.total_score = sum(grid.score for grid in self.grids)

    def draw(self):
        self.screen.fill((0, 0, 0))

        for grid in self.grids:
            grid.draw(self.screen)

        # Display Player Contributions
        for i, contribution in enumerate(self.player_contributions):
            text = self.font.render(f"Player {i+1} Contribution: {contribution:.2f}", True, (255, 255, 255))
            self.screen.blit(text, (10, HEIGHT + 10 + i * 30))

        # Display Total Score
        total_score_text = self.font.render(f"Total Score: {self.total_score}", True, (255, 255, 255))
        self.screen.blit(total_score_text, (10, HEIGHT + 100))

        # Display Game Over Message
        if self.game_over:
            game_over_text = self.font.render("Game Over! Press any key to exit.", True, (255, 0, 0))
            self.screen.blit(game_over_text, (WIDTH // 2 - game_over_text.get_width() // 2, HEIGHT // 2))

        pygame.display.flip()

    def run(self):
        running = True
        player_controls = [
            (pygame.K_LEFT, pygame.K_RIGHT, pygame.K_DOWN, pygame.K_UP, pygame.K_SPACE),  # Player 1
            (pygame.K_a, pygame.K_d, pygame.K_s, pygame.K_w, pygame.K_q),  # Player 2
            (pygame.K_j, pygame.K_l, pygame.K_k, pygame.K_i, pygame.K_u)   # Player 3
        ]

        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                for i in range(3):
                    self.handle_input(event, i)

            self.update()
            self.draw()

            if self.game_over:
                waiting = True
                while waiting:
                    for event in pygame.event.get():
                        if event.type == pygame.QUIT:
                            running = False
                            waiting = False
                        if event.type == pygame.KEYDOWN:
                            running = False
                            waiting = False

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

import pygame
import random
import time

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = (GRID_WIDTH * 3 + 6) * BLOCK_SIZE  # Three grids + spacing
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)

COLORS = [RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA, ORANGE]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]],  # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color

    def get_x(self):
        return self.x

    def get_y(self):
        return self.y

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

class Grid:
    def __init__(self, width, height, offset_x):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]
        self.offset_x = offset_x

    def is_valid_move(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    grid_x = x + j
                    grid_y = y + i
                    if (grid_x < 0 or grid_x >= self.width or grid_y >= self.height or
                            (grid_y >= 0 and self.grid[grid_y][grid_x] != 0)):
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        color = tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen):
        for i in range(self.height):
            for j in range(self.width):
                if self.grid[i][j]:
                    pygame.draw.rect(screen, self.grid[i][j],
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK,
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(screen, WHITE,
                                     (self.offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def is_game_over(self):
        return any(self.grid[0])

class Player:
    def __init__(self, player_id, grid):
        self.player_id = player_id
        self.grid = grid
        self.score = 0
        self.lines_cleared = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.choice(COLORS)
        return Tetromino(self.grid.width // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(self.current_tetromino):
            return False  # Game over
        return True

    def move_tetromino(self, dx):
        self.current_tetromino.move(dx, 0)
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.move(-dx, 0)

    def drop_tetromino(self):
        self.current_tetromino.move(0, 1)
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.move(0, -1)
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.lines_cleared += lines_cleared
            self.score += lines_cleared * lines_cleared * 100  # Example scoring
            self.current_tetromino = None
            return True  # Tetromino landed
        return False

    def rotate_tetromino(self):
        original_shape = [row[:] for row in self.current_tetromino.shape] # Deep copy
        self.current_tetromino.rotate()
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.shape = original_shape # Revert rotation

    def get_score(self):
        return self.score

    def get_lines_cleared(self):
