            for y in range(len(self.shape) - 1, -1, -1):
                new_row.append(self.shape[y][x])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color


class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_inside(self, x, y):
        return 0 <= x < self.width and 0 <= y < self.height

    def is_empty(self, x, y):
        return self.grid[y][x] == 0

    def is_valid_move(self, tetromino, x_offset, y_offset):
        shape = tetromino.get_shape()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    new_x = tetromino.x + x + x_offset
                    new_y = tetromino.y + y + y_offset
                    if not self.is_inside(new_x, new_y) or (self.is_inside(new_x, new_y) and not self.is_empty(new_x, new_y)):
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_shape()
        color = tetromino.get_color()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[tetromino.y + y][tetromino.x + x] = color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for y in range(self.height):
            if all(self.grid[y]):
                full_rows.append(y)

        for row in full_rows:
            del self.grid[row]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return not all(self.is_empty(x, 0) for x in range(self.width))

    def draw(self, screen, offset):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x]:
                    pygame.draw.rect(screen, self.grid[y][x],
