                                 (self.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, COLORS[7],
                                 (self.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)  # Grid lines

        # Draw tetromino
        if self.current_tetromino:
            for x, y in self.current_tetromino.get_cells():
                pygame.draw.rect(screen, COLORS[self.current_tetromino.color],
                                 (self.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, COLORS[7],
                                 (self.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)  # Grid lines

