                    players[0].move_tetromino_sideways(-1)
                if event.key == pygame.K_RIGHT:
                    players[0].move_tetromino_sideways(1)
                if event.key == pygame.K_UP:
                    players[0].rotate_tetromino()
                if event.key == pygame.K_a:
                    players[1].move_tetromino_sideways(-1)
                if event.key == pygame.K_d:
                    players[1].move_tetromino_sideways(1)
                if event.key == pygame.K_w:
                    players[1].rotate_tetromino()
                if event.key == pygame.K_j:
                    players[2].move_tetromino_sideways(-1)
                if event.key == pygame.K_l:
                    players[2].move_tetromino_sideways(1)
                if event.key == pygame.K_i:
                    players[2].rotate_tetromino()
                if event.key == pygame.K_SPACE:
                    for player in players:
                        while player.move_tetromino_down():
                            pass

        # Game logic
        fall_counter += 1
        for player in players:
            if not game_over[player.player_id]:
                if fall_counter >= fall_interval:
                    if not player.move_tetromino_down():
                        if not player.new_tetromino():
                            game_over[player.player_id] = True

        if fall_counter >= fall_interval:
            fall_counter = 0

        # Drawing
        screen.fill(COLORS[0])  # Black background
        for player in players:
            player.draw(screen)

        # Calculate and display total score and contributions
        total_score = sum(player.score for player in players)
        font = pygame.font.Font(None, 30)
        text = font.render(f"Total Score: {total_score}", True, COLORS[7])
        screen.blit(text, (SCREEN_WIDTH // 2 - text.get_width() // 2, SCREEN_HEIGHT))

        # Display individual contributions
        for i, player in enumerate(players):
            contribution_percentage = (player.contribution / total_score * 100) if total_score > 0 else 0
            contribution_text = font.render(f"Player {i+1} Contribution: {contribution_percentage:.2f}%", True, COLORS[7])
            screen.blit(contribution_text, (player.grid_x_offset, SCREEN_HEIGHT + 25))

        pygame.display.flip()
        clock.tick(FPS)

        if all(game_over):
            running = False

    pygame.quit()


if __name__ == "__main__":
