     [0, 0, 0]],

    [[0, 1, 0],
     [1, 1, 1],
     [0, 0, 0]]
]


class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        for x in range(len(self.shape[0])):
            new_row = []
            for y in range(len(self.shape) - 1, -1, -1):
                new_row.append(self.shape[y][x])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color


class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_inside(self, x, y):
        return 0 <= x < self.width and 0 <= y < self.height

    def is_empty(self, x, y):
        return self.grid[y][x] == 0

    def is_valid_move(self, tetromino, x_offset, y_offset):
        shape = tetromino.get_shape()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    new_x = tetromino.x + x + x_offset
                    new_y = tetromino.y + y + y_offset
                    if not self.is_inside(new_x, new_y) or (self.is_inside(new_x, new_y) and not self.is_empty(new_x, new_y)):
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_shape()
        color = tetromino.get_color()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[tetromino.y + y][tetromino.x + x] = color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for y in range(self.height):
            if all(self.grid[y]):
                full_rows.append(y)

        for row in full_rows:
            del self.grid[row]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return not all(self.is_empty(x, 0) for x in range(self.width))

    def draw(self, screen, offset):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x]:
                    pygame.draw.rect(screen, self.grid[y][x],
                                     (offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY,
                                     (offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(screen, BLACK,
                                     (offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY,
                                     (offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)


class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.grid_x_offset = grid_x_offset
        self.contribution = 0

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[SHAPES.index(shape)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino, 0, 0):
            return False  # Game Over
        return True

    def move_left(self):
        if self.current_tetromino and self.grid.is_valid_move(self.current_tetromino, -1, 0):
            self.current_tetromino.x -= 1

    def move_right(self):
        if self.current_tetromino and self.grid.is_valid_move(self.current_tetromino, 1, 0):
            self.current_tetromino.x += 1

    def move_down(self):
        if self.current_tetromino and self.grid.is_valid_move(self.current_tetromino, 0, 1):
            self.current_tetromino.y += 1
            return True
        return False

    def rotate(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino, 0, 0):
                self.current_tetromino.shape = original_shape  # Revert rotation

    def hard_drop(self):
        if self.current_tetromino:
            while self.grid.is_valid_move(self.current_tetromino, 0, 1):
                self.current_tetromino.y += 1
            self.lock_tetromino()

    def lock_tetromino(self):
        if self.current_tetromino:
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            if lines_cleared > 0:
                self.score += self.calculate_score(lines_cleared)
                self.contribution += lines_cleared
            self.current_tetromino = None

    def calculate_score(self, lines_cleared):
        if lines_cleared == 1:
            return 40
        elif lines_cleared == 2:
            return 100
        elif lines_cleared == 3:
            return 300
        elif lines_cleared == 4:
            return 1200
        return 0

    def draw_tetromino(self, screen):
        if self.current_tetromino:
            shape = self.current_tetromino.get_shape()
            color = self.current_tetromino.get_color()
            for y, row in enumerate(shape):
                for x, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(screen, color, (self.grid_x_offset + (self.current_tetromino.x + x) * BLOCK_SIZE,
                                                         (self.current_tetromino.y + y) * BLOCK_SIZE,
                                                         BLOCK_SIZE, BLOCK_SIZE))
                        pygame.draw.rect(screen, GRAY, (self.grid_x_offset + (self.current_tetromino.x + x) * BLOCK_SIZE,
                                                         (self.current_tetromino.y + y) * BLOCK_SIZE,
                                                         BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_next_tetromino(self, screen):
        font = pygame.font.Font(None, 24)
        text = font.render(f"Next:", True, WHITE)
        screen.blit(text, (self.grid_x_offset, SCREEN_HEIGHT + 10))

        shape = self.next_tetromino.get_shape()
        color = self.next_tetromino.get_color()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, color, (self.grid_x_offset + x * BLOCK_SIZE,
                                                     SCREEN_HEIGHT + 40 + y * BLOCK_SIZE,
                                                     BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY, (self.grid_x_offset + x * BLOCK_SIZE,
                                                     SCREEN_HEIGHT + 40 + y * BLOCK_SIZE,
                                                     BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_score(self, screen):
        font = pygame.font.Font(None, 36)
        text = font.render(f"Player {self.player_id + 1} Score: {self.score}", True, WHITE)
        screen.blit(text, (self.grid_x_offset, 20))

    def draw(self, screen):
        self.grid.draw(screen, self.grid_x_offset)
        self.draw_tetromino(screen)
        self.draw_next_tetromino(screen)
        self.draw_score(screen)


def main():
    pygame.init()
    screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT + 100))  # Increased height for next tetromino display
    pygame.display.set_caption("Collaborative Tetris")

    player1 = Player(0, 0)
    player2 = Player(1, GRID_WIDTH * BLOCK_SIZE)
    player3 = Player(2, GRID_WIDTH * BLOCK_SIZE * 2)
    players = [player1, player2, player3]

    game_over = False
    clock = pygame.time.Clock()
    fall_speed = 1  # Blocks per second
    fall_interval = 1 / fall_speed
    last_fall_time = 0

    for player in players:
        if not player.new_tetromino():
            game_over = True
            break

    def handle_input(event, player):
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT and player.player_id == 0:
                player.move_left()
            if event.key == pygame.K_RIGHT and player.player_id == 0:
                player.move_right()
            if event.key == pygame.K_DOWN and player.player_id == 0:
                player.move_down()
            if event.key == pygame.K_UP and player.player_id == 0:
                player.rotate()
            if event.key == pygame.K_SPACE and player.player_id == 0:
                player.hard_drop()

            if event.key == pygame.K_a and player.player_id == 1:
                player.move_left()
            if event.key == pygame.K_d and player.player_id == 1:
                player.move_right()
            if event.key == pygame.K_s and player.player_id == 1:
                player.move_down()
            if event.key == pygame.K_w and player.player_id == 1:
                player.rotate()
            if event.key == pygame.K_q and player.player_id == 1:
                player.hard_drop()

            if event.key == pygame.K_j and player.player_id == 2:
                player.move_left()
            if event.key == pygame.K_l and player.player_id == 2:
                player.move_right()
            if event.key == pygame.K_k and player.player_id == 2:
                player.move_down()
            if event.key == pygame.K_i and player.player_id == 2:
                player.rotate()
            if event.key == pygame.K_u and player.player_id == 2:
                player.hard_drop()

    def calculate_contributions():
        total_score = sum(player.score for player in players)
        if total_score == 0:
            return [0, 0, 0]
        contributions = [(player.contribution / total_score) * 100 for player in players]
        return contributions

    while not game_over:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                game_over = True
            for player in players:
                handle_input(event, player)

        current_time = pygame.time.get_ticks() / 1000  # Convert to seconds

        for player in players:
            if player.current_tetromino:
                if current_time - last_fall_time > fall_interval:
                    if not player.move_down():
                        player.lock_tetromino()
                        if not player.new_tetromino():
                            game_over = True
                            break
                    last_fall_time = current_time

        screen.fill(BLACK)

        for player in players:
            player.draw(screen)

        if game_over:
            font = pygame.font.Font(None, 72)
            text = font.render("Game Over!", True, WHITE)
            text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
            screen.blit(text, text_rect)

            contributions = calculate_contributions()
            font = pygame.font.Font(None, 36)
            for i, player in enumerate(players):
                contribution_text = font.render(f"Player {i+1} Contribution: {contributions[i]:.2f}%", True, WHITE)
                contribution_rect = contribution_text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2 + 50 + i * 40))
                screen.blit(contribution_text, contribution_rect)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()


if __name__ == "__main__":
    main()

