import pygame
import random
import sys

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = GRID_WIDTH * BLOCK_SIZE * 3 + 20  # Space for 3 grids + some padding
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)
COLORS = [GRAY, RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA, ORANGE]

class Piece:
    SHAPES = [
        [[1, 1, 1, 1]],  # I
        [[1, 1], [1, 1]],  # O
        [[0, 1, 1], [1, 1, 0]],  # Z
        [[1, 1, 0], [0, 1, 1]],  # S
        [[1, 0, 0], [1, 1, 1]],  # L
        [[0, 0, 1], [1, 1, 1]],  # J
        [[0, 1, 0], [1, 1, 1]]   # T
    ]

    def __init__(self, x, y, shape_index):
        self.x = x
        self.y = y
        self.shape = Piece.SHAPES[shape_index]
        self.color = COLORS[shape_index + 1]  # +1 to avoid gray
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for j in range(cols):
            new_row = []
            for i in range(rows - 1, -1, -1):
                new_row.append(self.shape[i][j])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, piece, x, y):
        for i in range(piece.get_height()):
            for j in range(piece.get_width()):
                if piece.shape[i][j]:
                    grid_x = x + j
                    grid_y = y + i
                    if grid_x < 0 or grid_x >= self.width or grid_y >= self.height:
                        return False
                    if grid_y >= 0 and self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def place_piece(self, piece, x, y):
        for i in range(piece.get_height()):
            for j in range(piece.get_width()):
                if piece.shape[i][j]:
                    self.grid[y + i][x + j] = piece.color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for i in range(self.height):
            if all(self.grid[i]):
                full_rows.append(i)

        for row in full_rows:
            del self.grid[row]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])

    def draw(self, screen, x_offset):
        for i in range(self.height):
            for j in range(self.width):
                if self.grid[i][j] != 0:
                    pygame.draw.rect(screen, self.grid[i][j],
                                     (x_offset + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                else:
                    pygame.draw.rect(screen, GRAY,
                                     (x_offset + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.score = 0
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.current_piece = None
        self.piece_x = GRID_WIDTH // 2 - 2
        self.piece_y = 0
        self.next_piece = self.create_piece()
        self.donation_percentage = 0.0  # Percentage of score donated to overall score

    def create_piece(self):
        return Piece(0, 0, random.randint(0, len(Piece.SHAPES) - 1))

    def new_piece(self):
        self.current_piece = self.next_piece
        self.piece_x = GRID_WIDTH // 2 - self.current_piece.get_width() // 2
        self.piece_y = 0
        self.next_piece = self.create_piece()
        if not self.grid.is_valid_move(self.current_piece, self.piece_x, self.piece_y):
            return True  # Game Over
        return False

    def move_piece(self, dx):
        if self.grid.is_valid_move(self.current_piece, self.piece_x + dx, self.piece_y):
            self.piece_x += dx

    def move_piece_down(self):
        if self.grid.is_valid_move(self.current_piece, self.piece_x, self.piece_y + 1):
            self.piece_y += 1
            return False
        else:
            self.grid.place_piece(self.current_piece, self.piece_x, self.piece_y)
            lines_cleared = self.grid.clear_lines()
            self.score += lines_cleared ** 2 * 100
            return True  # Piece landed

    def rotate_piece(self):
        original_shape = self.current_piece.shape
        self.current_piece.rotate()
        if not self.grid.is_valid_move(self.current_piece, self.piece_x, self.piece_y):
            self.current_piece.shape = original_shape  # Revert rotation

    def draw(self, screen, x_offset):
        self.grid.draw(screen, x_offset)
        if self.current_piece:
            for i in range(self.current_piece.get_height()):
                for j in range(self.current_piece.get_width()):
                    if self.current_piece.shape[i][j]:
                        pygame.draw.rect(screen, self.current_piece.color,
                                         (x_offset + (self.piece_x + j) * BLOCK_SIZE, (self.piece_y + i) * BLOCK_SIZE,
                                          BLOCK_SIZE, BLOCK_SIZE))

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [Player(i) for i in range(3)]
        self.game_over = False
        self.overall_score = 0
        self.font = pygame.font.Font(None, 36)
        self.drop_speed = 30 #frames
        self.drop_counter = 0

        for player in self.players:
            player.new_piece()

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.players[0].move_piece(-1)
                if event.key == pygame.K_RIGHT:
                    self.players[0].move_piece(1)
                if event.key == pygame.K_DOWN:
                    self.players[0].move_piece_down()
                if event.key == pygame.K_UP:
                    self.players[0].rotate_piece()

                if event.key == pygame.K_a:
                    self.players[1].move_piece(-1)
                if event.key == pygame.K_d:
                    self.players[1].move_piece(1)
                if event.key == pygame.K_s:
                    self.players[1].move_piece_down()
                if event.key == pygame.K_w:
                    self.players[1].rotate_piece()

                if event.key == pygame.K_j:
                    self.players[2].move_piece(-1)
                if event.key == pygame.K_l:
                    self.players[2].move_piece(1)
                if event.key == pygame.K_k:
                    self.players[2].move_piece_down()
                if event.key == pygame.K_i:
                    self.players[2].rotate_piece()

    def update(self):
        if not self.game_over:
            self.drop_counter += 1
            if self.drop_counter >= self.drop_speed:
                self.drop_counter = 0
                for player in self.players:
                    landed = player.move_piece_down()
                    if landed:
                        if player.new_piece():
                            self.game_over = True
                            break

            self.overall_score = sum(player.score * (1 + player.donation_percentage) for player in self.players)

    def draw(self):
        self.screen.fill(BLACK)
        for i, player in enumerate(self.players):
            player.draw(self.screen, i * GRID_WIDTH * BLOCK_SIZE + i * 10)  # Offset each grid

            score_text = self.font.render(f"Player {player.player_id + 1}: {player.score}", True, WHITE)
            self.screen.blit(score_text, (i * GRID_WIDTH * BLOCK_SIZE + i * 10, HEIGHT - 30))

        overall_score_text = self.font.render(f"Overall Score: {int(self.overall_score)}", True, WHITE)
        self.screen.blit(overall_score_text, (WIDTH // 2 - 150, HEIGHT - 60))

        if self.game_over:
            game_over_text = self.font.render("Game Over!", True, RED)
            self.screen.blit(game_over_text, (WIDTH // 2 - 80, HEIGHT // 2))

        pygame.display.flip()

    def run(self):
        while True:
            self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)

if __name__ == "__main__":
    game = Game()
    game.run()

