        if self.game_over:
            return
        self.current_tetromino.x -= 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x += 1

    def move_right(self):
        if self.game_over:
            return
        self.current_tetromino.x += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x -= 1

    def move_down(self):
        if self.game_over:
            return
        self.current_tetromino.y += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.y -= 1
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.score += lines_cleared ** 2 * 100
            self.new_tetromino()
            return True  # Indicate that the tetromino has landed
        return False

