        self.grid.draw(screen, self.offset_x)
        if self.current_tetromino:
            for x, y in self.current_tetromino.get_cells():
                pygame.draw.rect(screen, self.current_tetromino.color,
                                 (self.offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, BLACK,
                                 (self.offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

