        return self.score

    def is_game_over(self):
        return self.game_over

def calculate_donations(player_scores):
    total_score = sum(player_scores)
    if total_score == 0:
        return [1/len(player_scores)] * len(player_scores)  # Equal donation if no score
    donations = [score / total_score for score in player_scores]
    return donations

