HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
COLORS = [RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 1, 0], [0, 1, 1]],  # S
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]],  # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j]:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            if x < 0 or x >= self.width or y >= self.height or (y >= 0 and self.grid[y][x] != 0):
                return False
        return True

    def place_tetromino(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                lines_cleared += 1
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
        return lines_cleared

    def draw(self, screen, offset_x):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x]:
                    pygame.draw.rect(screen, self.grid[y][x],
                                     (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK,
                                     (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(screen, WHITE,
                                     (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

class Player:
    def __init__(self, player_id, grid_width, grid_height, offset_x):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.offset_x = offset_x
        self.game_over = False

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.choice(COLORS)
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino):
            self.game_over = True

    def move_left(self):
        if self.game_over:
            return
        self.current_tetromino.x -= 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x += 1

