class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Tetris for Three")
        self.clock = pygame.time.Clock()
        self.players = [Player(i) for i in range(3)]
        self.game_over = [False] * 3
        self.font = pygame.font.Font(None, 36)
        self.frame_count = 0

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    self.players[0].move_left()
                elif event.key == pygame.K_d:
                    self.players[0].move_right()
                elif event.key == pygame.K_w:
                    self.players[0].rotate()
                elif event.key == pygame.K_s:
                    self.players[0].drop()

                elif event.key == pygame.K_j:
                    self.players[1].move_left()
                elif event.key == pygame.K_l:
                    self.players[1].move_right()
                elif event.key == pygame.K_i:
                    self.players[1].rotate()
                elif event.key == pygame.K_k:
                    self.players[1].drop()

                elif event.key == pygame.K_LEFT:
                    self.players[2].move_left()
                elif event.key == pygame.K_RIGHT:
                    self.players[2].move_right()
                elif event.key == pygame.K_UP:
                    self.players[2].rotate()
                elif event.key == pygame.K_DOWN:
                    self.players[2].drop()
        return True

    def update(self):
        for i in range(3):
            if not self.game_over[i]:
                if self.frame_count % (FPS // 2) == 0: # Adjust speed
                    self.game_over[i] = self.players[i].update()

    def draw(self):
        self.screen.fill(BLACK)
        for i in range(3):
            self.players[i].draw(self.screen, i * GRID_WIDTH * BLOCK_SIZE)
            score_text = self.font.render(f"Player {i+1}: {self.players[i].score}", True, WHITE)
            self.screen.blit(score_text, (i * GRID_WIDTH * BLOCK_SIZE, HEIGHT - 30))

        pygame.display.flip()

    def calculate_contributions(self):
        total_lines_cleared = sum(player.lines_cleared for player in self.players)
        if total_lines_cleared == 0:
            return [0] * 3
        return [player.lines_cleared / total_lines_cleared for player in self.players]

    def run(self):
        running = True
        while running:
            running = self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)
            self.frame_count += 1

            if all(self.game_over):
                contributions = self.calculate_contributions()
                print("Game Over!")
                for i in range(3):
                    print(f"Player {i+1} Contribution: {contributions[i]:.2f}")
                running = False

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

