        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, shape, offset_x, offset_y):
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    grid_x = offset_x + x
                    grid_y = offset_y + y
                    if (grid_x < 0 or grid_x >= self.width or
                            grid_y >= self.height or
                            (grid_y >= 0 and self.grid[grid_y][grid_x] != 0)):
                        return False
        return True

    def place_shape(self, shape, offset_x, offset_y, color_index):
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[offset_y + y][offset_x + x] = color_index + 1

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])

    def draw(self, screen, offset_x):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x]:
                    color = COLORS[self.grid[y][x] - 1]
                    pygame.draw.rect(screen, color,
                                     (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                else:
                    pygame.draw.rect(screen, GRAY,
                                     (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

class Piece:
    def __init__(self, shape=None):
        if shape is None:
            self.shape = random.choice(SHAPES)
        else:
            self.shape = shape
        self.color_index = random.randint(0, len(COLORS) - 1)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.current_piece = Piece()
        self.next_piece = Piece()
        self.score = 0
        self.lines_cleared = 0
        self.contribution = 0

    def update(self):
        if self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y + 1):
            self.current_piece.y += 1
        else:
            self.grid.place_shape(self.current_piece.shape, self.current_piece.x, self.current_piece.y, self.current_piece.color_index)
            lines = self.grid.clear_lines()
            self.lines_cleared += lines
            self.score += lines ** 2 * 100
            self.current_piece = self.next_piece
            self.next_piece = Piece()
            if self.grid.is_game_over():
                return True  # Game over for this player
        return False

    def move_left(self):
        if self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x - 1, self.current_piece.y):
            self.current_piece.x -= 1

    def move_right(self):
        if self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x + 1, self.current_piece.y):
            self.current_piece.x += 1

    def rotate(self):
        original_shape = [row[:] for row in self.current_piece.shape]
        self.current_piece.rotate()
        if not self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y):
            self.current_piece.shape = original_shape

    def drop(self):
        while self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y + 1):
            self.current_piece.y += 1
        self.grid.place_shape(self.current_piece.shape, self.current_piece.x, self.current_piece.y, self.current_piece.color_index)
        lines = self.grid.clear_lines()
        self.lines_cleared += lines
        self.score += lines ** 2 * 100
        self.current_piece = self.next_piece
        self.next_piece = Piece()
        if self.grid.is_game_over():
            return True
        return False

    def draw(self, screen, offset_x):
        self.grid.draw(screen, offset_x)
        for y, row in enumerate(self.current_piece.shape):
            for x, cell in enumerate(row):
                if cell:
                    color = COLORS[self.current_piece.color_index]
                    pygame.draw.rect(screen, color,
                                     (offset_x + (self.current_piece.x + x) * BLOCK_SIZE,
                                      (self.current_piece.y + y) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Tetris for Three")
        self.clock = pygame.time.Clock()
        self.players = [Player(i) for i in range(3)]
        self.game_over = [False] * 3
        self.font = pygame.font.Font(None, 36)
        self.frame_count = 0

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    self.players[0].move_left()
                elif event.key == pygame.K_d:
                    self.players[0].move_right()
                elif event.key == pygame.K_w:
                    self.players[0].rotate()
                elif event.key == pygame.K_s:
                    self.players[0].drop()

                elif event.key == pygame.K_j:
                    self.players[1].move_left()
                elif event.key == pygame.K_l:
                    self.players[1].move_right()
                elif event.key == pygame.K_i:
                    self.players[1].rotate()
                elif event.key == pygame.K_k:
                    self.players[1].drop()

                elif event.key == pygame.K_LEFT:
                    self.players[2].move_left()
                elif event.key == pygame.K_RIGHT:
                    self.players[2].move_right()
                elif event.key == pygame.K_UP:
                    self.players[2].rotate()
                elif event.key == pygame.K_DOWN:
                    self.players[2].drop()
        return True

    def update(self):
        for i in range(3):
            if not self.game_over[i]:
                if self.frame_count % (FPS // 2) == 0: # Adjust speed
                    self.game_over[i] = self.players[i].update()

    def draw(self):
        self.screen.fill(BLACK)
        for i in range(3):
            self.players[i].draw(self.screen, i * GRID_WIDTH * BLOCK_SIZE)
            score_text = self.font.render(f"Player {i+1}: {self.players[i].score}", True, WHITE)
            self.screen.blit(score_text, (i * GRID_WIDTH * BLOCK_SIZE, HEIGHT - 30))

        pygame.display.flip()

    def calculate_contributions(self):
        total_lines_cleared = sum(player.lines_cleared for player in self.players)
        if total_lines_cleared == 0:
            return [0] * 3
        return [player.lines_cleared / total_lines_cleared for player in self.players]

    def run(self):
        running = True
        while running:
            running = self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)
            self.frame_count += 1

            if all(self.game_over):
                contributions = self.calculate_contributions()
                print("Game Over!")
                for i in range(3):
                    print(f"Player {i+1} Contribution: {contributions[i]:.2f}")
                running = False

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

