            lines_text = font.render(f"Lines: {player.get_lines_cleared()}", True, WHITE)
            contribution_text = font.render(f"Contribution: {player.get_contribution():.2f}%", True, WHITE)
            game_over_text = font.render("GAME OVER", True, RED)

            self.screen.blit(name_text, (offset, SCREEN_HEIGHT + 10))
            self.screen.blit(score_text, (offset, SCREEN_HEIGHT + 40))
            self.screen.blit(lines_text, (offset, SCREEN_HEIGHT + 70))
            self.screen.blit(contribution_text, (offset, SCREEN_HEIGHT + 100))

