    def __init__(self, players):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH * 3, SCREEN_HEIGHT))  # Triple width for 3 players
        pygame.display.set_caption("Tetris Quislingism")
        self.clock = pygame.time.Clock()
        self.players = players
        self.grids = [Grid(GRID_WIDTH, GRID_HEIGHT) for _ in range(len(players))]
        self.current_pieces = [self.new_piece() for _ in range(len(players))]
        self.game_over = [False] * len(players)
        self.fall_speed = 1  # Blocks per second
        self.fall_time = 1000 / self.fall_speed
        self.last_fall_time = pygame.time.get_ticks()
        self.total_score = 0

    def new_piece(self):
        shape = random.choice(SHAPES)
        return Piece(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape)

    def run(self):
        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                if event.type == pygame.KEYDOWN:
                    for i, player in enumerate(self.players):
                        if not self.game_over[i]:
                            if event.key == pygame.K_LEFT and i == 0:
                                if self.grids[i].is_valid_move(self.current_pieces[i], -1, 0):
                                    self.current_pieces[i].set_x(self.current_pieces[i].get_x() - 1)
                            if event.key == pygame.K_RIGHT and i == 0:
                                if self.grids[i].is_valid_move(self.current_pieces[i], 1, 0):
                                    self.current_pieces[i].set_x(self.current_pieces[i].get_x() + 1)
                            if event.key == pygame.K_DOWN and i == 0:
                                if self.grids[i].is_valid_move(self.current_pieces[i], 0, 1):
                                    self.current_pieces[i].set_y(self.current_pieces[i].get_y() + 1)
                            if event.key == pygame.K_UP and i == 0:
                                original_shape = self.current_pieces[i].get_shape()
                                self.current_pieces[i].rotate()
                                if not self.grids[i].is_valid_move(self.current_pieces[i], 0, 0):
                                    self.current_pieces[i].set_shape(original_shape)
                                else:
                                    self.current_pieces[i].set_shape(self.current_pieces[i].get_shape())

                            if event.key == pygame.K_a and i == 1:
                                if self.grids[i].is_valid_move(self.current_pieces[i], -1, 0):
                                    self.current_pieces[i].set_x(self.current_pieces[i].get_x() - 1)
                            if event.key == pygame.K_d and i == 1:
                                if self.grids[i].is_valid_move(self.current_pieces[i], 1, 0):
                                    self.current_pieces[i].set_x(self.current_pieces[i].get_x() + 1)
                            if event.key == pygame.K_s and i == 1:
                                if self.grids[i].is_valid_move(self.current_pieces[i], 0, 1):
                                    self.current_pieces[i].set_y(self.current_pieces[i].get_y() + 1)
                            if event.key == pygame.K_w and i == 1:
                                original_shape = self.current_pieces[i].get_shape()
                                self.current_pieces[i].rotate()
                                if not self.grids[i].is_valid_move(self.current_pieces[i], 0, 0):
                                    self.current_pieces[i].set_shape(original_shape)
                                else:
                                    self.current_pieces[i].set_shape(self.current_pieces[i].get_shape())

                            if event.key == pygame.K_j and i == 2:
                                if self.grids[i].is_valid_move(self.current_pieces[i], -1, 0):
                                    self.current_pieces[i].set_x(self.current_pieces[i].get_x() - 1)
                            if event.key == pygame.K_l and i == 2:
                                if self.grids[i].is_valid_move(self.current_pieces[i], 1, 0):
                                    self.current_pieces[i].set_x(self.current_pieces[i].get_x() + 1)
                            if event.key == pygame.K_k and i == 2:
                                if self.grids[i].is_valid_move(self.current_pieces[i], 0, 1):
                                    self.current_pieces[i].set_y(self.current_pieces[i].get_y() + 1)
                            if event.key == pygame.K_i and i == 2:
                                original_shape = self.current_pieces[i].get_shape()
                                self.current_pieces[i].rotate()
                                if not self.grids[i].is_valid_move(self.current_pieces[i], 0, 0):
                                    self.current_pieces[i].set_shape(original_shape)
                                else:
                                    self.current_pieces[i].set_shape(self.current_pieces[i].get_shape())

            now = pygame.time.get_ticks()
            for i, player in enumerate(self.players):
                if not self.game_over[i]:
                    if now - self.last_fall_time > self.fall_time:
                        self.last_fall_time = now
                        if self.grids[i].is_valid_move(self.current_pieces[i], 0, 1):
                            self.current_pieces[i].set_y(self.current_pieces[i].get_y() + 1)
                        else:
                            self.grids[i].place_piece(self.current_pieces[i])
                            lines_cleared = self.grids[i].clear_lines()
                            self.players[i].add_lines_cleared(lines_cleared)
                            score = lines_cleared * 100
                            self.players[i].add_score(score)
                            self.total_score += score
                            self.current_pieces[i] = self.new_piece()
                            if not self.grids[i].is_valid_move(self.current_pieces[i], 0, 0):
                                self.game_over[i] = True

            # Update player contributions
            for player in self.players:
                player.update_contribution(self.total_score)

            self.draw()
            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

    def draw(self):
        self.screen.fill(BLACK)
        for i, player in enumerate(self.players):
            grid = self.grids[i].get_grid()
            piece = self.current_pieces[i]
