import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * BLOCK_SIZE
SCREEN_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30

# Colors
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [
    (0, 255, 255),  # Cyan
    (0, 0, 255),    # Blue
    (255, 127, 0),  # Orange
    (255, 255, 0),  # Yellow
    (0, 255, 0),    # Green
    (255, 0, 0),    # Red
    (128, 0, 128)   # Purple
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape_index):
        self.x = x
        self.y = y
        self.shape = SHAPES[shape_index]
        self.color = COLORS[shape_index]
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])

        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_rotated_shape(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])

        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        return rotated_shape

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino, x, y):
        for i in range(tetromino.get_height()):
            for j in range(tetromino.get_width()):
                if tetromino.shape[i][j]:
                    grid_x = x + j
                    grid_y = y + i

                    if grid_x < 0 or grid_x >= self.width or grid_y >= self.height:
                        return False
                    if grid_y >= 0 and self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def place_tetromino(self, tetromino):
        for i in range(tetromino.get_height()):
            for j in range(tetromino.get_width()):
                if tetromino.shape[i][j]:
                    self.grid[tetromino.y + i][tetromino.x + j] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for i in range(self.height):
            if all(self.grid[i]):
                full_rows.append(i)

        for row in full_rows:
            del self.grid[row]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0][i] != 0 for i in range(self.width))

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.score = 0
        self.lines_cleared = 0
        self.contribution = 0.0

    def update_score(self, lines_cleared):
        if lines_cleared == 1:
            self.score += 40
        elif lines_cleared == 2:
            self.score += 100
        elif lines_cleared == 3:
            self.score += 300
        elif lines_cleared == 4:
            self.score += 1200
        self.lines_cleared += lines_cleared

class Game:
    def __init__(self, num_players):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH * (num_players + 1), SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris Quislingism")
        self.clock = pygame.time.Clock()
        self.num_players = num_players
        self.grids = [Grid(GRID_WIDTH, GRID_HEIGHT) for _ in range(num_players)]
        self.players = [Player(i) for i in range(num_players)]
        self.current_tetrominoes = [self.new_tetromino() for _ in range(num_players)]
        self.tetromino_x = [GRID_WIDTH // 2 - self.current_tetrominoes[i].get_width() // 2 for i in range(num_players)]
        self.tetromino_y = [0 for _ in range(num_players)]
        self.game_over = [False] * num_players
        self.font = pygame.font.Font(None, 36)
        self.total_lines_cleared = 0

    def new_tetromino(self):
        return Tetromino(0, 0, random.randint(0, len(SHAPES) - 1))

    def handle_input(self, player_id, event):
        if self.game_over[player_id]:
            return

        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT:
                if self.grids[player_id].is_valid_move(self.current_tetrominoes[player_id], self.tetromino_x[player_id] - 1, self.tetromino_y[player_id]):
                    self.tetromino_x[player_id] -= 1
            elif event.key == pygame.K_RIGHT:
                if self.grids[player_id].is_valid_move(self.current_tetrominoes[player_id], self.tetromino_x[player_id] + 1, self.tetromino_y[player_id]):
                    self.tetromino_x[player_id] += 1
            elif event.key == pygame.K_DOWN:
                if self.grids[player_id].is_valid_move(self.current_tetrominoes[player_id], self.tetromino_x[player_id], self.tetromino_y[player_id] + 1):
                    self.tetromino_y[player_id] += 1
            elif event.key == pygame.K_UP:
                rotated_tetromino = Tetromino(self.tetromino_x[player_id], self.tetromino_y[player_id], SHAPES.index(self.current_tetrominoes[player_id].shape))
                rotated_tetromino.shape = self.current_tetrominoes[player_id].get_rotated_shape()
                if self.grids[player_id].is_valid_move(rotated_tetromino, self.tetromino_x[player_id], self.tetromino_y[player_id]):
                    self.current_tetrominoes[player_id].rotate()
            elif event.key == pygame.K_SPACE:
                while self.grids[player_id].is_valid_move(self.current_tetrominoes[player_id], self.tetromino_x[player_id], self.tetromino_y[player_id] + 1):
                    self.tetromino_y[player_id] += 1
                self.lock_tetromino(player_id)

    def lock_tetromino(self, player_id):
        self.current_tetrominoes[player_id].x = self.tetromino_x[player_id]
        self.current_tetrominoes[player_id].y = self.tetromino_y[player_id]
        self.grids[player_id].place_tetromino(self.current_tetrominoes[player_id])
        lines_cleared = self.grids[player_id].clear_lines()
        self.players[player_id].update_score(lines_cleared)
        self.total_lines_cleared += lines_cleared
        self.current_tetrominoes[player_id] = self.new_tetromino()
        self.tetromino_x[player_id] = GRID_WIDTH // 2 - self.current_tetrominoes[player_id].get_width() // 2
        self.tetromino_y[player_id] = 0
        if self.grids[player_id].is_game_over():
            self.game_over[player_id] = True

    def update(self):
        for player_id in range(self.num_players):
            if not self.game_over[player_id]:
                if self.grids[player_id].is_valid_move(self.current_tetrominoes[player_id], self.tetromino_x[player_id], self.tetromino_y[player_id] + 1):
                    self.tetromino_y[player_id] += 1
                else:
                    self.lock_tetromino(player_id)

    def calculate_contributions(self):
        if self.total_lines_cleared == 0:
            for player in self.players:
                player.contribution = 0.0
        else:
            for player in self.players:
                player.contribution = player.lines_cleared / self.total_lines_cleared

    def draw_grid(self, screen, grid, offset_x):
        for i in range(grid.height):
            for j in range(grid.width):
                if grid.grid[i][j] != 0:
                    pygame.draw.rect(screen, grid.grid[i][j], (offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY, (offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(screen, BLACK, (offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY, (offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_tetromino(self, screen, tetromino, x, y, offset_x):
        for i in range(tetromino.get_height()):
            for j in range(tetromino.get_width()):
                if tetromino.shape[i][j]:
                    pygame.draw.rect(screen, tetromino.color, (offset_x + (x + j) * BLOCK_SIZE, (y + i) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY, (offset_x + (x + j) * BLOCK_SIZE, (y + i) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_scores(self, screen):
        for i, player in enumerate(self.players):
            score_text = self.font.render(f"Player {player.player_id + 1}: {player.score}", True, WHITE)
            screen.blit(score_text, (SCREEN_WIDTH * i, SCREEN_HEIGHT + 10))
            contribution_text = self.font.render(f"Contribution: {player.contribution:.2f}", True, WHITE)
            screen.blit(contribution_text, (SCREEN_WIDTH * i, SCREEN_HEIGHT + 50))

    def render(self):
        self.screen.fill(BLACK)
        for i in range(self.num_players):
            self.draw_grid(self.screen, self.grids[i], SCREEN_WIDTH * i)
            if not self.game_over[i]:
                self.draw_tetromino(self.screen, self.current_tetrominoes[i], self.tetromino_x[i], self.tetromino_y[i], SCREEN_WIDTH * i)

        self.draw_scores(self.screen)

        game_over_offset = SCREEN_WIDTH * self.num_players
        for i in range(self.num_players):
            if self.game_over[i]:
                game_over_text = self.font.render(f"Player {i+1} Game Over", True, WHITE)
                text_rect = game_over_text.get_rect(center=(game_over_offset + SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2 + (i * 50)))
                self.screen.blit(game_over_text, text_rect)

        pygame.display.flip()

    def run(self):
        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                else:
                    for i in range(self.num_players):
                        self.handle_input(i, event)

            self.update()
            self.calculate_contributions()
            self.render()
            self.clock.tick(FPS)

            if all(self.game_over):
                running = False

        pygame.quit()

if __name__ == '__main__':
    num_players = 3  # You can change this to 2 or 3
    game = Game(num_players)
    game.run()

