        elif lines_cleared == 2:
            self.score += 100
        elif lines_cleared == 3:
            self.score += 300
        elif lines_cleared == 4:
            self.score += 1200
        self.lines_cleared += lines_cleared

    def update_contribution(self, total_score):
        if total_score > 0:
            self.contribution = (self.score / total_score) * 100
        else:
            self.contribution = 0

    def get_contribution(self):
        return self.contribution

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Trinity Tetris")
        self.clock = pygame.time.Clock()
        self.players = [Player(1), Player(2), Player(3)]
        self.current_pieces = [self.new_piece() for _ in range(3)]
        self.game_over = False
        self.total_score = 0

    def new_piece(self):
        shape = random.choice(SHAPES)
        color = COLORS[random.randint(1, len(COLORS) - 1)] # Avoid black
        return Piece(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def run(self):
        running = True
        fall_counter = 0
        fall_speed = 30 # Adjust for difficulty

        while running:
            self.screen.fill(BLACK)

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                if event.type == pygame.KEYDOWN:
                    if not self.game_over:
                        if event.key == pygame.K_a: # Player 1 left
                            if self.players[0].get_grid().is_valid_move(self.current_pieces[0], -1, 0):
                                self.current_pieces[0].set_x(self.current_pieces[0].get_x() - 1)
                        if event.key == pygame.K_d: # Player 1 right
                            if self.players[0].get_grid().is_valid_move(self.current_pieces[0], 1, 0):
                                self.current_pieces[0].set_x(self.current_pieces[0].get_x() + 1)
                        if event.key == pygame.K_s: # Player 1 down
                            if self.players[0].get_grid().is_valid_move(self.current_pieces[0], 0, 1):
                                self.current_pieces[0].set_y(self.current_pieces[0].get_y() + 1)
                            else:
                                self.lock_piece(0)
                        if event.key == pygame.K_q: # Player 1 rotate
                            rotated_piece = Piece(self.current_pieces[0].get_x(), self.current_pieces[0].get_y(), [row[:] for row in self.current_pieces[0].get_shape()], self.current_pieces[0].get_color())
                            rotated_piece.rotate()
                            if self.players[0].get_grid().is_valid_move(rotated_piece, 0, 0):
                                self.current_pieces[0].rotate()

                        if event.key == pygame.K_j: # Player 2 left
                            if self.players[1].get_grid().is_valid_move(self.current_pieces[1], -1, 0):
                                self.current_pieces[1].set_x(self.current_pieces[1].get_x() - 1)
                        if event.key == pygame.K_l: # Player 2 right
                            if self.players[1].get_grid().is_valid_move(self.current_pieces[1], 1, 0):
                                self.current_pieces[1].set_x(self.current_pieces[1].get_x() + 1)
                        if event.key == pygame.K_k: # Player 2 down
                            if self.players[1].get_grid().is_valid_move(self.current_pieces[1], 0, 1):
                                self.current_pieces[1].set_y(self.current_pieces[1].get_y() + 1)
                            else:
                                self.lock_piece(1)
                        if event.key == pygame.K_i: # Player 2 rotate
                            rotated_piece = Piece(self.current_pieces[1].get_x(), self.current_pieces[1].get_y(), [row[:] for row in self.current_pieces[1].get_shape()], self.current_pieces[1].get_color())
                            rotated_piece.rotate()
                            if self.players[1].get_grid().is_valid_move(rotated_piece, 0, 0):
                                self.current_pieces[1].rotate()

                        if event.key == pygame.K_LEFT: # Player 3 left
                            if self.players[2].get_grid().is_valid_move(self.current_pieces[2], -1, 0):
                                self.current_pieces[2].set_x(self.current_pieces[2].get_x() - 1)
                        if event.key == pygame.K_RIGHT: # Player 3 right
                            if self.players[2].get_grid().is_valid_move(self.current_pieces[2], 1, 0):
                                self.current_pieces[2].set_x(self.current_pieces[2].get_x() + 1)
                        if event.key == pygame.K_DOWN: # Player 3 down
                            if self.players[2].get_grid().is_valid_move(self.current_pieces[2], 0, 1):
                                self.current_pieces[2].set_y(self.current_pieces[2].get_y() + 1)
                            else:
                                self.lock_piece(2)
                        if event.key == pygame.K_UP: # Player 3 rotate
                            rotated_piece = Piece(self.current_pieces[2].get_x(), self.current_pieces[2].get_y(), [row[:] for row in self.current_pieces[2].get_shape()], self.current_pieces[2].get_color())
                            rotated_piece.rotate()
                            if self.players[2].get_grid().is_valid_move(rotated_piece, 0, 0):
                                self.current_pieces[2].rotate()

            if not self.game_over:
                fall_counter += 1
                if fall_counter >= fall_speed:
                    fall_counter = 0
                    for i in range(3):
                        if self.players[i].get_grid().is_valid_move(self.current_pieces[i], 0, 1):
                            self.current_pieces[i].set_y(self.current_pieces[i].get_y() + 1)
                        else:
                            self.lock_piece(i)

            self.draw_grids()
            self.draw_scores()

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

    def lock_piece(self, player_index):
        self.players[player_index].get_grid().place_piece(self.current_pieces[player_index])
        lines_cleared = self.players[player_index].get_grid().clear_lines()
        self.players[player_index].update_score(lines_cleared)
        self.total_score = sum(player.get_score() for player in self.players)
        for player in self.players:
            player.update_contribution(self.total_score)
        self.current_pieces[player_index] = self.new_piece()
        if self.players[player_index].get_grid().is_game_over():
            self.game_over = True

    def draw_grids(self):
        for i in range(3):
            grid = self.players[i].get_grid().get_grid()
            offset = i * (GRID_WIDTH * BLOCK_SIZE)
            for row_index, row in enumerate(grid):
                for col_index, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(self.screen, COLORS[cell], (offset + col_index * BLOCK_SIZE, row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    else:
                        pygame.draw.rect(self.screen, GRAY, (offset + col_index * BLOCK_SIZE, row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

            # Draw the current piece
            piece = self.current_pieces[i]
            shape = piece.get_shape()
            color = piece.get_color()
            for row_index, row in enumerate(shape):
                for col_index, cell in enumerate(row):
                    if cell:
                        x = piece.get_x() + col_index
                        y = piece.get_y() + row_index
                        if 0 <= x < GRID_WIDTH and 0 <= y < GRID_HEIGHT:
                            pygame.draw.rect(self.screen, color, (offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def draw_scores(self):
        font = pygame.font.Font(None, 36)
        x_offset = GRID_WIDTH * BLOCK_SIZE * 3 + 20

        for i, player in enumerate(self.players):
            y_offset = 50 + i * 100
            score_text = font.render(f"Player {player.get_player_id()} Score: {player.get_score()}", True, WHITE)
            lines_text = font.render(f"Lines: {player.get_lines_cleared()}", True, WHITE)
            contribution_text = font.render(f"Contribution: {player.get_contribution():.2f}%", True, WHITE)

            self.screen.blit(score_text, (x_offset, y_offset))
            self.screen.blit(lines_text, (x_offset, y_offset + 30))
            self.screen.blit(contribution_text, (x_offset, y_offset + 60))

if __name__ == "__main__":
    game = Game()
    game.run()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = GRID_WIDTH * BLOCK_SIZE * 3  # Triple width for 3 players
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
COLORS = [
    (0, 0, 0),       # Black (Empty)
    (0, 255, 255),   # Cyan (I)
    (0, 0, 255),     # Blue (J)
    (255, 165, 0),   # Orange (L)
    (255, 255, 0),   # Yellow (O)
    (0, 255, 0),     # Green (S)
    (255, 0, 0),     # Red (Z)
    (128, 0, 128)    # Purple (T)
]

SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Piece:
    def __init__(self, x, y, shape):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = random.randint(1, len(COLORS) - 1)
        self.rotation = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        return rotated_shape

    def get_shape(self):
        rotated_shape = self.shape
        for _ in range(self.rotation):
            rotated_shape = list(zip(*rotated_shape[::-1]))
        return rotated_shape

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, piece, x_offset, y_offset):
        shape = piece.get_shape()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    grid_x = piece.x + x + x_offset
                    grid_y = piece.y + y + y_offset

                    if grid_x < 0 or grid_x >= self.width or grid_y >= self.height:
                        return False
                    if grid_y >= 0 and self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def place_piece(self, piece):
        shape = piece.get_shape()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[piece.y + y][piece.x + x] = piece.color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for i, row in enumerate(self.grid):
            if all(cell != 0 for cell in row):
                full_rows.append(i)

        for row_index in full_rows:
            del self.grid[row_index]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0][x] != 0 for x in range(self.width))

class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.current_piece = None
        self.next_piece = self.new_piece()
        self.grid_x_offset = grid_x_offset
        self.lines_cleared = 0
        self.contribution = 0

    def new_piece(self):
        shape = random.choice(SHAPES)
        return Piece(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape)

    def update(self):
        if self.current_piece is None:
            self.current_piece = self.next_piece
            self.next_piece = self.new_piece()
            if not self.grid.is_valid_move(self.current_piece, 0, 0):
                return False # Game Over

        if self.grid.is_valid_move(self.current_piece, 0, 1):
            self.current_piece.y += 1
        else:
            self.grid.place_piece(self.current_piece)
            lines = self.grid.clear_lines()
            self.lines_cleared += lines
            self.score += lines ** 2 * 100
            self.contribution += lines ** 2 * 100
            self.current_piece = None
        return True

    def move_left(self):
        if self.current_piece and self.grid.is_valid_move(self.current_piece, -1, 0):
            self.current_piece.x -= 1

    def move_right(self):
        if self.current_piece and self.grid.is_valid_move(self.current_piece, 1, 0):
            self.current_piece.x += 1

    def rotate(self):
        if self.current_piece:
            original_rotation = self.current_piece.rotation
            self.current_piece.rotation = (self.current_piece.rotation + 1) % 4
            if not self.grid.is_valid_move(self.current_piece, 0, 0):
                self.current_piece.rotation = original_rotation

    def drop(self):
        if self.current_piece:
            while self.grid.is_valid_move(self.current_piece, 0, 1):
                self.current_piece.y += 1
            self.grid.place_piece(self.current_piece)
            lines = self.grid.clear_lines()
            self.lines_cleared += lines
            self.score += lines ** 2 * 100
            self.contribution += lines ** 2 * 100
            self.current_piece = None

def draw_grid(screen, grid, x_offset):
    for y, row in enumerate(grid.grid):
        for x, cell in enumerate(row):
            if cell:
                pygame.draw.rect(screen, COLORS[cell], (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, (128, 128, 128), (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_piece(screen, piece, x_offset):
    if piece:
        shape = piece.get_shape()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, COLORS[piece.color], (x_offset + (piece.x + x) * BLOCK_SIZE, (piece.y + y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, (128, 128, 128), (x_offset + (piece.x + x) * BLOCK_SIZE, (piece.y + y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_next_piece(screen, piece, x_offset, y_offset):
    if piece:
        shape = piece.get_shape()
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, COLORS[piece.color], (x_offset + x * BLOCK_SIZE, y_offset + y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, (128, 128, 128), (x_offset + x * BLOCK_SIZE, y_offset + y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_score(screen, player, x_offset, y_offset):
    font = pygame.font.Font(None, 36)
    text = font.render(f"Player {player.player_id + 1} Score: {player.score}", True, (255, 255, 255))
    screen.blit(text, (x_offset, y_offset))

def draw_contribution(screen, player, x_offset, y_offset):
    font = pygame.font.Font(None, 24)
    text = font.render(f"Contribution: {player.contribution}", True, (255, 255, 255))
    screen.blit(text, (x_offset, y_offset))

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Trinity Tetris")

    players = [
        Player(0, 0),
        Player(1, GRID_WIDTH * BLOCK_SIZE),
        Player(2, GRID_WIDTH * BLOCK_SIZE * 2)
    ]

    clock = pygame.time.Clock()
    fall_speed = 30  # Frames per drop
    fall_counter = 0
    game_over = [False, False, False]

    running = True
    while running:
        screen.fill((0, 0, 0))

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    players[0].move_left()
                if event.key == pygame.K_RIGHT:
                    players[0].move_right()
                if event.key == pygame.K_UP:
                    players[0].rotate()
                if event.key == pygame.K_DOWN:
                    players[0].drop()

                if event.key == pygame.K_a:
                    players[1].move_left()
                if event.key == pygame.K_d:
                    players[1].move_right()
                if event.key == pygame.K_w:
                    players[1].rotate()
                if event.key == pygame.K_s:
                    players[1].drop()

                if event.key == pygame.K_j:
                    players[2].move_left()
                if event.key == pygame.K_l:
                    players[2].move_right()
                if event.key == pygame.K_i:
                    players[2].rotate()
                if event.key == pygame.K_k:
                    players[2].drop()

        fall_counter += 1
        for i, player in enumerate(players):
            if not game_over[i]:
                if fall_counter >= fall_speed:
                    fall_counter = 0
                    if not player.update():
                        game_over[i] = True

        for i, player in enumerate(players):
            draw_grid(screen, player.grid, player.grid_x_offset)
            draw_piece(screen, player.current_piece, player.grid_x_offset)
            draw_next_piece(screen, player.next_piece, player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE // 2 - BLOCK_SIZE * 2, HEIGHT - BLOCK_SIZE * 5)
            draw_score(screen, player, player.grid_x_offset, 10)
            draw_contribution(screen, player, player.grid_x_offset, 50)

            if game_over[i]:
                font = pygame.font.Font(None, 72)
                text = font.render(f"Player {i+1} Game Over", True, (255, 0, 0))
                text_rect = text.get_rect(center=(player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE // 2, HEIGHT // 2))
                screen.blit(text, text_rect)

        pygame.display.flip()
        clock.tick(FPS)

    total_score = sum(player.score for player in players)
    if total_score > 0:
        for player in players:
            player.contribution = round(player.score / total_score * 100, 2)
    else:
        for player in players:
            player.contribution = 0

    print("Game Over!")
    for i, player in enumerate(players):
        print(f"Player {i+1}: Score = {player.score}, Contribution = {player.contribution}%")

    pygame.quit()

if __name__ == "__main__":
    main()

