            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, COLORS[piece.color], (x_offset + x * BLOCK_SIZE, y_offset + y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, (128, 128, 128), (x_offset + x * BLOCK_SIZE, y_offset + y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_score(screen, player, x_offset, y_offset):
    font = pygame.font.Font(None, 36)
    text = font.render(f"Player {player.player_id + 1} Score: {player.score}", True, (255, 255, 255))
    screen.blit(text, (x_offset, y_offset))

def draw_contribution(screen, player, x_offset, y_offset):
    font = pygame.font.Font(None, 24)
    text = font.render(f"Contribution: {player.contribution}", True, (255, 255, 255))
    screen.blit(text, (x_offset, y_offset))

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Trinity Tetris")

    players = [
        Player(0, 0),
        Player(1, GRID_WIDTH * BLOCK_SIZE),
        Player(2, GRID_WIDTH * BLOCK_SIZE * 2)
    ]

    clock = pygame.time.Clock()
    fall_speed = 30  # Frames per drop
    fall_counter = 0
    game_over = [False, False, False]

    running = True
    while running:
        screen.fill((0, 0, 0))

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    players[0].move_left()
                if event.key == pygame.K_RIGHT:
                    players[0].move_right()
                if event.key == pygame.K_UP:
                    players[0].rotate()
                if event.key == pygame.K_DOWN:
                    players[0].drop()

                if event.key == pygame.K_a:
                    players[1].move_left()
                if event.key == pygame.K_d:
                    players[1].move_right()
                if event.key == pygame.K_w:
                    players[1].rotate()
                if event.key == pygame.K_s:
                    players[1].drop()

                if event.key == pygame.K_j:
                    players[2].move_left()
                if event.key == pygame.K_l:
                    players[2].move_right()
                if event.key == pygame.K_i:
                    players[2].rotate()
                if event.key == pygame.K_k:
                    players[2].drop()

        fall_counter += 1
        for i, player in enumerate(players):
            if not game_over[i]:
                if fall_counter >= fall_speed:
                    fall_counter = 0
                    if not player.update():
                        game_over[i] = True

        for i, player in enumerate(players):
            draw_grid(screen, player.grid, player.grid_x_offset)
            draw_piece(screen, player.current_piece, player.grid_x_offset)
            draw_next_piece(screen, player.next_piece, player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE // 2 - BLOCK_SIZE * 2, HEIGHT - BLOCK_SIZE * 5)
            draw_score(screen, player, player.grid_x_offset, 10)
            draw_contribution(screen, player, player.grid_x_offset, 50)

            if game_over[i]:
                font = pygame.font.Font(None, 72)
                text = font.render(f"Player {i+1} Game Over", True, (255, 0, 0))
                text_rect = text.get_rect(center=(player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE // 2, HEIGHT // 2))
                screen.blit(text, text_rect)

        pygame.display.flip()
        clock.tick(FPS)

    total_score = sum(player.score for player in players)
    if total_score > 0:
        for player in players:
            player.contribution = round(player.score / total_score * 100, 2)
    else:
        for player in players:
            player.contribution = 0

    print("Game Over!")
    for i, player in enumerate(players):
        print(f"Player {i+1}: Score = {player.score}, Contribution = {player.contribution}%")

    pygame.quit()

if __name__ == "__main__":
    main()

import pygame
import random

# Define some colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
