BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)

COLORS = [GRAY, RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA]

# Define some constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * BLOCK_SIZE * 3 + 200 # Space for 3 grids and scores
SCREEN_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30

# Define the shapes of the Tetris pieces
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Piece:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])

        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color

    def get_x(self):
        return self.x

    def get_y(self):
        return self.y

    def set_x(self, x):
        self.x = x

    def set_y(self, y):
        self.y = y

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]

    def is_valid_move(self, piece, x_offset, y_offset):
        shape = piece.get_shape()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    x = piece.get_x() + j + x_offset
                    y = piece.get_y() + i + y_offset

                    if x < 0 or x >= self.width or y >= self.height:
                        return False
                    if y >= 0 and self.grid[y][x] != 0:
                        return False
        return True

    def place_piece(self, piece):
        shape = piece.get_shape()
        color = piece.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    x = piece.get_x() + j
                    y = piece.get_y() + i
                    self.grid[y][x] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def get_grid(self):
        return self.grid

    def is_game_over(self):
        return any(self.grid[0])

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.lines_cleared = 0
        self.contribution = 0 #Contribution to the overall score

    def get_grid(self):
        return self.grid

