                if event.key == pygame.K_u and not game_over[1]:
                    player2.rotate()

                if event.key == pygame.K_LEFT and not game_over[2]:
                    player3.move_left()
                if event.key == pygame.K_RIGHT and not game_over[2]:
                    player3.move_right()
                if event.key == pygame.K_DOWN and not game_over[2]:
                    player3.move_down()
                if event.key == pygame.K_UP and not game_over[2]:
                    player3.rotate()

        for i, player in enumerate(players):
            if not game_over[i]:
                tick_counter += 1
                if tick_counter >= fall_ticks:
                    tick_counter = 0
                    if player.move_down():
                        if not player.new_tetromino():
                            game_over[i] = True

        # Drawing
        for player in players:
            draw_grid(screen, player.grid, player.grid_x_offset)
            draw_tetromino(screen, player.current_tetromino, player.grid_x_offset)
            draw_next_tetromino(screen, player.next_tetromino, player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE + 10, 50)
            draw_score(screen, player.score, player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE + 10, 10, font)

        pygame.display.flip()

    pygame.quit()

if __name__ == "__main__":
