import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = (GRID_WIDTH * 3 + 2) * BLOCK_SIZE  # Space for 3 grids + 2 gaps
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [(0, 255, 255), (0, 0, 255), (255, 127, 0), (255, 255, 0), (0, 255, 0), (255, 0, 0), (128, 0, 128)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

class TetrisGrid:
    def __init__(self, x_offset):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.x_offset = x_offset
        self.current_piece = None
        self.piece_x = 0
        self.piece_y = 0
        self.score = 0
        self.game_over = False
        self.next_piece = self.new_piece()

    def new_piece(self):
        return random.randint(0, len(SHAPES) - 1)

    def spawn_piece(self):
        self.current_piece = self.next_piece
        self.next_piece = self.new_piece()
        self.piece_x = GRID_WIDTH // 2 - len(SHAPES[self.current_piece][0]) // 2
        self.piece_y = 0
        if not self.is_valid_position(self.piece_x, self.piece_y, self.current_piece):
            self.game_over = True

    def rotate_piece(self):
        rotated_piece = list(zip(*reversed(SHAPES[self.current_piece])))
        if self.is_valid_position(self.piece_x, self.piece_y, rotated_piece):
            SHAPES[self.current_piece] = rotated_piece

    def move_piece(self, dx):
        if self.is_valid_position(self.piece_x + dx, self.piece_y, self.current_piece):
            self.piece_x += dx

    def drop_piece(self):
        while self.is_valid_position(self.piece_x, self.piece_y + 1, self.current_piece):
            self.piece_y += 1
        self.lock_piece()

    def is_valid_position(self, x, y, piece_index):
        piece = SHAPES[piece_index]
        for i in range(len(piece)):
            for j in range(len(piece[0])):
                if piece[i][j]:
                    grid_x = x + j
                    grid_y = y + i
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT or self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def lock_piece(self):
        piece = SHAPES[self.current_piece]
        for i in range(len(piece)):
            for j in range(len(piece[0])):
                if piece[i][j]:
                    self.grid[self.piece_y + i][self.piece_x + j] = self.current_piece + 1
        self.clear_lines()
        self.spawn_piece()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        if lines_cleared > 0:
            self.score += 100 * (lines_cleared ** 2)

    def draw(self, screen):
        # Draw grid
        for i in range(GRID_HEIGHT):
            for j in range(GRID_WIDTH):
                if self.grid[i][j]:
                    pygame.draw.rect(screen, COLORS[self.grid[i][j] - 1],
                                     (self.x_offset + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                else:
                    pygame.draw.rect(screen, GRAY,
                                     (self.x_offset + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

        # Draw current piece
        if self.current_piece is not None:
            piece = SHAPES[self.current_piece]
            for i in range(len(piece)):
                for j in range(len(piece[0])):
                    if piece[i][j]:
                        pygame.draw.rect(screen, COLORS[self.current_piece],
                                         (self.x_offset + (self.piece_x + j) * BLOCK_SIZE, (self.piece_y + i) * BLOCK_SIZE,
                                          BLOCK_SIZE, BLOCK_SIZE))

        # Draw next piece preview
        font = pygame.font.Font(None, 30)
        text = font.render("Next:", True, WHITE)
        screen.blit(text, (self.x_offset, HEIGHT + 10))

        next_piece = SHAPES[self.next_piece]
        for i in range(len(next_piece)):
            for j in range(len(next_piece[0])):
                if next_piece[i][j]:
                    pygame.draw.rect(screen, COLORS[self.next_piece],
                                     (self.x_offset + j * BLOCK_SIZE, HEIGHT + 40 + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

        # Draw score
        score_text = font.render(f"Score: {self.score}", True, WHITE)
        screen.blit(score_text, (self.x_offset, HEIGHT + 150))

class TerzettoTetris:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT + 200))
        pygame.display.set_caption("Terzetto Tetris")
        self.clock = pygame.time.Clock()
        self.grids = [TetrisGrid(i * (GRID_WIDTH + 1) * BLOCK_SIZE) for i in range(3)]
        self.player_names = ["Player 1", "Player 2", "Player 3"]
        self.player_controls = {
            0: {'left': pygame.K_a, 'right': pygame.K_d, 'rotate': pygame.K_s, 'drop': pygame.K_w},
            1: {'left': pygame.K_j, 'right': pygame.K_l, 'rotate': pygame.K_k, 'drop': pygame.K_i},
            2: {'left': pygame.K_LEFT, 'right': pygame.K_RIGHT, 'rotate': pygame.K_UP, 'drop': pygame.K_DOWN}
        }
        self.game_over = False
        self.font = pygame.font.Font(None, 36)
        self.frame_count = 0
        self.drop_speed = 30  # Drop every 30 frames initially

        for grid in self.grids:
            grid.spawn_piece()

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                for player_id, controls in self.player_controls.items():
                    if event.key == controls['left']:
                        self.grids[player_id].move_piece(-1)
                    if event.key == controls['right']:
