        rotated_shape = self.shape
        for _ in range(rotation):
            rotated_shape = list(zip(*rotated_shape[::-1]))
        return rotated_shape

    def get_current_shape(self):
        return self.get_rotated_shape(self.rotation)

    def width(self):
        return len(self.get_current_shape()[0])

    def height(self):
        return len(self.get_current_shape())

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]
        self.player_contributions = [[0] * width for _ in range(height)] # Track player contributions

    def is_valid_move(self, tetromino, x, y, rotation):
        shape = tetromino.get_rotated_shape(rotation)
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    grid_x = x + j
                    grid_y = y + i
                    if grid_x < 0 or grid_x >= self.width or grid_y >= self.height or self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_current_shape()
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    self.grid[tetromino.y + i][tetromino.x + j] = 1
                    self.player_contributions[tetromino.y + i][tetromino.x + j] = tetromino.player_id + 1 # Store player ID (1, 2, or 3)

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for i in range(self.height):
            if all(self.grid[i]):
                full_rows.append(i)

        for row in full_rows:
            del self.grid[row]
            del self.player_contributions[row]
            self.grid.insert(0, [0] * self.width)
            self.player_contributions.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def get_player_contribution_score(self, lines_cleared):
        player_scores = [0, 0, 0]
        for _ in range(lines_cleared):
            contribution_counts = [0, 0, 0]
            for row in self.player_contributions:
                for player_id in row:
                    if player_id > 0:
                        contribution_counts[player_id - 1] += 1

            total_blocks = sum(contribution_counts)
            if total_blocks > 0:
                for i in range(3):
                    player_scores[i] += contribution_counts[i] / total_blocks if total_blocks > 0 else 0
        return player_scores

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.grids = [Grid(GRID_WIDTH, GRID_HEIGHT) for _ in range(3)]
        self.current_tetrominoes = [None] * 3
        self.next_tetrominoes = [None] * 3
        self.player_scores = [0, 0, 0]
        self.game_over = False
        self.player_turn = 0  # Start with player 0
        self.font = pygame.font.Font(None, 36)

        for i in range(3):
            self.next_tetrominoes[i] = self.new_tetromino(i)
            self.current_tetrominoes[i] = self.new_tetromino(i)

    def new_tetromino(self, player_id):
        shape = random.choice(SHAPES)
        x = GRID_WIDTH // 2 - len(shape[0]) // 2
        y = 0
        return Tetromino(x, y, shape, player_id)

    def draw_grid(self, grid, offset_x):
        for i in range(grid.height):
            for j in range(grid.width):
                if grid.grid[i][j]:
                    player_id = grid.player_contributions[i][j] - 1
                    color = PLAYER_COLORS[player_id]
                    pygame.draw.rect(self.screen, color, (offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                else:
                    pygame.draw.rect(self.screen, GRID_COLOR, (offset_x + j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_tetromino(self, tetromino, offset_x):
        if tetromino:
            shape = tetromino.get_current_shape()
            for i in range(len(shape)):
                for j in range(len(shape[0])):
                    if shape[i][j]:
                        pygame.draw.rect(self.screen, tetromino.color, (offset_x + (tetromino.x + j) * BLOCK_SIZE, (tetromino.y + i) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def draw_next_tetromino(self, tetromino, offset_x, offset_y):
        if tetromino:
            shape = tetromino.get_current_shape()
            for i in range(len(shape)):
                for j in range(len(shape[0])):
                    if shape[i][j]:
                        pygame.draw.rect(self.screen, tetromino.color, (offset_x + j * BLOCK_SIZE, offset_y + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def draw_scores(self):
        for i in range(3):
            text = self.font.render(f"Player {i+1}: {self.player_scores[i]:.2f}", True, PLAYER_COLORS[i])
            self.screen.blit(text, (10 + i * (GRID_WIDTH * BLOCK_SIZE), HEIGHT - 40))

    def run(self):
        running = True
        drop_time = pygame.time.get_ticks()
        drop_speed = 500  # Milliseconds

        while running:
            self.clock.tick(FPS)
            self.screen.fill(BACKGROUND_COLOR)

            # Event handling
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                if event.type == pygame.KEYDOWN and not self.game_over:
                    if event.key == pygame.K_LEFT:
                        if self.grids[self.player_turn].is_valid_move(self.current_tetrominoes[self.player_turn], self.current_tetrominoes[self.player_turn].x - 1, self.current_tetrominoes[self.player_turn].y, self.current_tetrominoes[self.player_turn].rotation):
                            self.current_tetrominoes[self.player_turn].x -= 1
                    if event.key == pygame.K_RIGHT:
                        if self.grids[self.player_turn].is_valid_move(self.current_tetrominoes[self.player_turn], self.current_tetrominoes[self.player_turn].x + 1, self.current_tetrominoes[self.player_turn].y, self.current_tetrominoes[self.player_turn].rotation):
                            self.current_tetrominoes[self.player_turn].x += 1
                    if event.key == pygame.K_DOWN:
                        if self.grids[self.player_turn].is_valid_move(self.current_tetrominoes[self.player_turn], self.current_tetrominoes[self.player_turn].x, self.current_tetrominoes[self.player_turn].y + 1, self.current_tetrominoes[self.player_turn].rotation):
                            self.current_tetrominoes[self.player_turn].y += 1
                    if event.key == pygame.K_UP:
                        rotated_rotation = (self.current_tetrominoes[self.player_turn].rotation + 1) % 4
                        if self.grids[self.player_turn].is_valid_move(self.current_tetrominoes[self.player_turn], self.current_tetrominoes[self.player_turn].x, self.current_tetrominoes[self.player_turn].y, rotated_rotation):
                            self.current_tetrominoes[self.player_turn].rotation = rotated_rotation
                    if event.key == pygame.K_SPACE:
                        while self.grids[self.player_turn].is_valid_move(self.current_tetrominoes[self.player_turn], self.current_tetrominoes[self.player_turn].x, self.current_tetrominoes[self.player_turn].y + 1, self.current_tetrominoes[self.player_turn].rotation):
                            self.current_tetrominoes[self.player_turn].y += 1
                        self.lock_tetromino()

            # Game logic
            if not self.game_over:
                if pygame.time.get_ticks() - drop_time > drop_speed:
                    drop_time = pygame.time.get_ticks()
                    if self.grids[self.player_turn].is_valid_move(self.current_tetrominoes[self.player_turn], self.current_tetrominoes[self.player_turn].x, self.current_tetrominoes[self.player_turn].y + 1, self.current_tetrominoes[self.player_turn].rotation):
                        self.current_tetrominoes[self.player_turn].y += 1
                    else:
                        self.lock_tetromino()

            # Drawing
            for i in range(3):
                self.draw_grid(self.grids[i], i * GRID_WIDTH * BLOCK_SIZE)
                self.draw_tetromino(self.current_tetrominoes[i], i * GRID_WIDTH * BLOCK_SIZE)
                self.draw_next_tetromino(self.next_tetrominoes[i], i * GRID_WIDTH * BLOCK_SIZE + GRID_WIDTH * BLOCK_SIZE + 10, 10)

            self.draw_scores()

            if self.game_over:
                text = self.font.render("Game Over!", True, (255, 255, 255))
                self.screen.blit(text, (WIDTH // 2 - 80, HEIGHT // 2 - 20))

            pygame.display.flip()

        pygame.quit()

    def lock_tetromino(self):
        self.grids[self.player_turn].place_tetromino(self.current_tetrominoes[self.player_turn])
        lines_cleared = self.grids[self.player_turn].clear_lines()
        player_contribution_scores = self.grids[self.player_turn].get_player_contribution_score(lines_cleared)
        for i in range(3):
            self.player_scores[i] += player_contribution_scores[i]

        self.current_tetrominoes[self.player_turn] = self.next_tetrominoes[self.player_turn]
        self.next_tetrominoes[self.player_turn] = self.new_tetromino(self.player_turn)
        self.current_tetrominoes[self.player_turn].x = GRID_WIDTH // 2 - self.current_tetrominoes[self.player_turn].width() // 2
        self.current_tetrominoes[self.player_turn].y = 0

        if not self.grids[self.player_turn].is_valid_move(self.current_tetrominoes[self.player_turn], self.current_tetrominoes[self.player_turn].x, self.current_tetrominoes[self.player_turn].y, self.current_tetrominoes[self.player_turn].rotation):
            self.game_over = True

        self.player_turn = (self.player_turn + 1) % 3  # Switch to the next player

if __name__ == "__main__":
