    game.run()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE * 3  # Three players
HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
          (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])

        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j]:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            if x < 0 or x >= self.width or y >= self.height or self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

class Player:
    def __init__(self, player_id, x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.x_offset = x_offset
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.randint(1, len(COLORS) - 1)
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino):
            return False # Game Over
        return True

    def move_left(self):
        if self.current_tetromino:
            self.current_tetromino.x -= 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x += 1

    def move_right(self):
        if self.current_tetromino:
            self.current_tetromino.x += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= 1

    def move_down(self):
        if self.current_tetromino:
            self.current_tetromino.y += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.grid.place_tetromino(self.current_tetromino)
                lines_cleared = self.grid.clear_lines()
                self.score += lines_cleared ** 2 * 100
                return False # Tetromino landed
            return True # Tetromino moved down
        return False

    def rotate(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape # Revert rotation

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [Player(1, 0), Player(2, GRID_WIDTH * CELL_SIZE), Player(3, GRID_WIDTH * CELL_SIZE * 2)]
        self.game_over = False
        self.fall_speed = 1
        self.fall_counter = 0
        self.font = pygame.font.Font(None, 36)

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    self.players[0].move_left()
                if event.key == pygame.K_d:
                    self.players[0].move_right()
                if event.key == pygame.K_s:
                    self.players[0].move_down()
                if event.key == pygame.K_q:
                    self.players[0].rotate()

                if event.key == pygame.K_j:
                    self.players[1].move_left()
                if event.key == pygame.K_l:
                    self.players[1].move_right()
                if event.key == pygame.K_k:
                    self.players[1].move_down()
                if event.key == pygame.K_u:
                    self.players[1].rotate()

                if event.key == pygame.K_LEFT:
                    self.players[2].move_left()
                if event.key == pygame.K_RIGHT:
                    self.players[2].move_right()
                if event.key == pygame.K_DOWN:
                    self.players[2].move_down()
                if event.key == pygame.K_UP:
                    self.players[2].rotate()

    def update(self):
        if self.game_over:
            return

        self.fall_counter += self.fall_speed
        for player in self.players:
            if player.current_tetromino is None:
                if not player.new_tetromino():
                    self.game_over = True
                    return

            if self.fall_counter >= FPS:
                if not player.move_down():
                    player.current_tetromino = None
                self.fall_counter = 0

    def draw_grid(self, screen, grid, x_offset):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = COLORS[grid[y][x]]
                pygame.draw.rect(screen, color, (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                pygame.draw.rect(screen, COLORS[7], (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_tetromino(self, screen, tetromino, x_offset):
        if tetromino:
            for x, y in tetromino.get_cells():
                pygame.draw.rect(screen, COLORS[tetromino.color], (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                pygame.draw.rect(screen, COLORS[7], (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_next_tetromino(self, screen, tetromino, x_offset):
        if tetromino:
            for i in range(len(tetromino.shape)):
                for j in range(len(tetromino.shape[0])):
                    if tetromino.shape[i][j]:
                        pygame.draw.rect(screen, COLORS[tetromino.color], (x_offset + (j + GRID_WIDTH + 1) * CELL_SIZE, (i + 2) * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                        pygame.draw.rect(screen, COLORS[7], (x_offset + (j + GRID_WIDTH + 1) * CELL_SIZE, (i + 2) * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_score(self, screen, score, x_offset):
        text = self.font.render(f"Score: {score}", True, COLORS[7])
        screen.blit(text, (x_offset, HEIGHT - 50))

    def draw(self):
        self.screen.fill(COLORS[0])

        for player in self.players:
            self.draw_grid(self.screen, player.grid.grid, player.x_offset)
            self.draw_tetromino(self.screen, player.current_tetromino, player.x_offset)
            self.draw_next_tetromino(self.screen, player.next_tetromino, player.x_offset)
            self.draw_score(self.screen, player.score, player.x_offset)

        if self.game_over:
            text = self.font.render("Game Over!", True, COLORS[7])
            text_rect = text.get_rect(center=(WIDTH // 2, HEIGHT // 2))
            self.screen.blit(text, text_rect)

            total_score = sum(player.score for player in self.players)
            contributions = [(player.player_id, player.score / total_score if total_score else 0) for player in self.players]

            y_offset = HEIGHT // 2 + 50
            for player_id, contribution in contributions:
                contribution_text = self.font.render(f"Player {player_id}: {contribution:.2%}", True, COLORS[7])
                contribution_rect = contribution_text.get_rect(center=(WIDTH // 2, y_offset))
                self.screen.blit(contribution_text, contribution_rect)
                y_offset += 30

        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

