    font = pygame.font.Font(None, 36)
    score_text = font.render(f"Player {player_id} Score: {score}", True, WHITE)
    level_text = font.render(f"Level: {level}", True, WHITE)
    screen.blit(score_text, (offset_x, offset_y))
    screen.blit(level_text, (offset_x, offset_y + 40))

def main():
    pygame.init()
    screen = pygame.display.set_mode((SCREEN_WIDTH * 3 + 200, SCREEN_HEIGHT))
    pygame.display.set_caption("Tetris for Three")

    tetris_games = [Tetris(1), Tetris(2), Tetris(3)]
    player_scores = [0, 0, 0]  # Keep track of individual scores
    game_over_flags = [False, False, False]

    clock = pygame.time.Clock()

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                for i, tetris in enumerate(tetris_games):
                    if not tetris.is_game_over():
                        if event.key == PLAYER_CONTROLS[i+1]['left']:
                            tetris.move_left()
                        elif event.key == PLAYER_CONTROLS[i+1]['right']:
                            tetris.move_right()
                        elif event.key == PLAYER_CONTROLS[i+1]['rotate']:
                            tetris.rotate()
                        elif event.key == PLAYER_CONTROLS[i+1]['drop']:
                            tetris.hard_drop()

        screen.fill(BLACK)

        # Update and draw each Tetris game
        for i, tetris in enumerate(tetris_games):
            if not tetris.is_game_over():
                tetris.drop()
                player_scores[i] = tetris.get_score()
            else:
                game_over_flags[i] = True

            offset_x = i * (SCREEN_WIDTH + 50)
            offset_y = 0

            draw_grid(screen, tetris.get_grid(), offset_x, offset_y)
            draw_piece(screen, tetris.get_current_piece(), offset_x, offset_y)
            draw_score(screen, tetris.get_score(), tetris.get_level(), offset_x, SCREEN_HEIGHT, i + 1)

            # Draw next piece
            next_piece_offset_x = offset_x + GRID_WIDTH * BLOCK_SIZE + 10
            next_piece_offset_y = 50
            draw_next_piece(screen, tetris.get_next_piece(), next_piece_offset_x, next_piece_offset_y)

            if tetris.is_game_over():
                font = pygame.font.Font(None, 72)
                game_over_text = font.render("Game Over", True, WHITE)
                text_rect = game_over_text.get_rect(center=(offset_x + SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
                screen.blit(game_over_text, text_rect)

        # Calculate and display combined score (example: average)
        if all(game_over_flags):
            total_score = sum(player_scores)
            average_score = total_score / 3 if total_score > 0 else 0
            font = pygame.font.Font(None, 48)
            combined_score_text = font.render(f"Combined Score: {average_score:.2f}", True, WHITE)
            text_rect = combined_score_text.get_rect(center=(SCREEN_WIDTH * 1.5, SCREEN_HEIGHT - 100))
            screen.blit(combined_score_text, text_rect)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()

