            self.game_over = True

    def draw(self, screen, offset_x):
        self.grid.draw(screen, offset_x)
        self.piece.draw(screen, offset_x)

    def calculate_contribution(self, total_score):
        if total_score == 0:
            self.contribution = 0
        else:
            self.contribution = self.score / total_score

