    def __init__(self, grid):
        self.grid = grid
        self.shape = random.choice(SHAPES)
        self.color_index = random.randint(0, len(COLORS) - 1)
        self.x = grid.width // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        if self.grid.is_valid_move(rotated_shape, self.x, self.y):
            self.shape = rotated_shape

    def move(self, dx):
        if self.grid.is_valid_move(self.shape, self.x + dx, self.y):
            self.x += dx

    def move_down(self):
        if self.grid.is_valid_move(self.shape, self.x, self.y + 1):
            self.y += 1
            return True
        else:
            return False

    def draw(self, screen, offset_x):
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j]:
                    pygame.draw.rect(screen, COLORS[self.color_index],
                                     (offset_x + (self.x + j) * BLOCK_SIZE,
                                      (self.y + i) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))

class Player:
    def __init__(self, player_id, grid, controls):
        self.player_id = player_id
        self.grid = grid
        self.piece = Piece(grid)
        self.score = 0
        self.controls = controls  # Dictionary of controls: rotate, left, right, down
        self.game_over = False
        self.lines_cleared = 0
        self.contribution = 0 # How much this player contributed to the overall score

    def update(self, events):
        for event in events:
            if event.type == pygame.KEYDOWN:
                if event.key == self.controls['rotate']:
                    self.piece.rotate()
                elif event.key == self.controls['left']:
                    self.piece.move(-1)
                elif event.key == self.controls['right']:
                    self.piece.move(1)
                elif event.key == self.controls['down']:
                    if not self.piece.move_down():
                        self.lock_piece()

    def lock_piece(self):
        self.grid.place_shape(self.piece.shape, self.piece.x, self.piece.y, self.piece.color_index)
        lines_cleared = self.grid.clear_lines()
        self.lines_cleared += lines_cleared
        self.score += lines_cleared ** 2 * 100  # Example scoring
        self.piece = Piece(self.grid)
        if not self.grid.is_valid_move(self.piece.shape, self.piece.x, self.piece.y):
            self.game_over = True

    def draw(self, screen, offset_x):
        self.grid.draw(screen, offset_x)
        self.piece.draw(screen, offset_x)

    def calculate_contribution(self, total_score):
        if total_score == 0:
            self.contribution = 0
        else:
            self.contribution = self.score / total_score

# Game setup
