import pygame
import random
import time

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * BLOCK_SIZE
SCREEN_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30

# Colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
COLORS = [(0, 255, 255), (0, 0, 255), (255, 127, 0), (255, 255, 0),
          (0, 255, 0), (255, 0, 0), (128, 0, 128)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

# Player controls (example - can be customized)
PLAYER_CONTROLS = {
    1: {'left': pygame.K_a, 'right': pygame.K_d, 'rotate': pygame.K_s, 'drop': pygame.K_w},
    2: {'left': pygame.K_j, 'right': pygame.K_l, 'rotate': pygame.K_k, 'drop': pygame.K_i},
    3: {'left': pygame.K_LEFT, 'right': pygame.K_RIGHT, 'rotate': pygame.K_UP, 'drop': pygame.K_DOWN}
}

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_current_shape(self):
        return self.shape

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)

class Tetris:
    def __init__(self, player_id):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_piece = None
        self.next_piece = self.new_piece()
        self.game_over = False
        self.score = 0
        self.player_id = player_id
        self.level = 1
        self.drop_speed = 1  # Blocks per second
        self.last_drop_time = time.time()

    def new_piece(self):
        shape = random.choice(SHAPES)
        color = COLORS[SHAPES.index(shape)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def generate_piece(self):
        self.current_piece = self.next_piece
        self.next_piece = self.new_piece()
        if not self.is_valid_position(self.current_piece, 0, 0):
            self.game_over = True

    def is_valid_position(self, piece, x_offset, y_offset):
        for y in range(piece.get_height()):
            for x in range(piece.get_width()):
                if piece.get_current_shape()[y][x]:
                    grid_x = piece.x + x + x_offset
                    grid_y = piece.y + y + y_offset
                    if (grid_x < 0 or grid_x >= GRID_WIDTH or
                            grid_y >= GRID_HEIGHT or
                            self.grid[grid_y][grid_x] != 0):
                        return False
        return True

    def lock_piece(self):
        for y in range(self.current_piece.get_height()):
            for x in range(self.current_piece.get_width()):
                if self.current_piece.get_current_shape()[y][x]:
                    self.grid[self.current_piece.y + y][self.current_piece.x + x] = self.current_piece.color
        self.clear_lines()
        self.generate_piece()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1

        if lines_cleared > 0:
            points = [40, 100, 300, 1200]
            self.score += points[lines_cleared - 1] * self.level
            self.level = self.score // 1000 + 1
            self.drop_speed = 1 + (self.level - 1) * 0.2  # Increase drop speed

    def drop(self):
        if self.game_over:
            return

        if self.current_piece is None:
            self.generate_piece()
            return

        if time.time() - self.last_drop_time >= (1 / self.drop_speed):
            if self.is_valid_position(self.current_piece, 0, 1):
                self.current_piece.y += 1
            else:
                self.lock_piece()
            self.last_drop_time = time.time()

    def move_left(self):
        if self.current_piece and self.is_valid_position(self.current_piece, -1, 0):
            self.current_piece.x -= 1

    def move_right(self):
        if self.current_piece and self.is_valid_position(self.current_piece, 1, 0):
            self.current_piece.x += 1

    def rotate(self):
        if self.current_piece:
            original_shape = self.current_piece.shape
            self.current_piece.rotate()
            if not self.is_valid_position(self.current_piece, 0, 0):
                self.current_piece.shape = original_shape  # Revert rotation

    def hard_drop(self):
        if self.current_piece:
            while self.is_valid_position(self.current_piece, 0, 1):
                self.current_piece.y += 1
            self.lock_piece()

    def get_grid(self):
        return self.grid

    def get_current_piece(self):
        return self.current_piece

    def get_next_piece(self):
        return self.next_piece

    def get_score(self):
        return self.score

    def get_level(self):
        return self.level

    def is_game_over(self):
        return self.game_over

def draw_grid(screen, grid, offset_x, offset_y):
    for y in range(GRID_HEIGHT):
        for x in range(GRID_WIDTH):
            if grid[y][x] != 0:
                pygame.draw.rect(screen, grid[y][x],
                                 (offset_x + x * BLOCK_SIZE, offset_y + y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, GRAY,
                                 (offset_x + x * BLOCK_SIZE, offset_y + y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE), 1)
            else:
                pygame.draw.rect(screen, BLACK,
                                 (offset_x + x * BLOCK_SIZE, offset_y + y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, GRAY,
                                 (offset_x + x * BLOCK_SIZE, offset_y + y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_piece(screen, piece, offset_x, offset_y):
    if piece:
        for y in range(piece.get_height()):
            for x in range(piece.get_width()):
                if piece.get_current_shape()[y][x]:
                    pygame.draw.rect(screen, piece.color,
                                     (offset_x + (piece.x + x) * BLOCK_SIZE,
                                      offset_y + (piece.y + y) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY,
                                     (offset_x + (piece.x + x) * BLOCK_SIZE,
                                      offset_y + (piece.y + y) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_next_piece(screen, piece, offset_x, offset_y):
    if piece:
        for y in range(piece.get_height()):
            for x in range(piece.get_width()):
                if piece.get_current_shape()[y][x]:
                    pygame.draw.rect(screen, piece.color,
                                     (offset_x + x * BLOCK_SIZE,
                                      offset_y + y * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, GRAY,
                                     (offset_x + x * BLOCK_SIZE,
                                      offset_y + y * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_score(screen, score, level, offset_x, offset_y, player_id):
    font = pygame.font.Font(None, 36)
    score_text = font.render(f"Player {player_id} Score: {score}", True, WHITE)
    level_text = font.render(f"Level: {level}", True, WHITE)
    screen.blit(score_text, (offset_x, offset_y))
    screen.blit(level_text, (offset_x, offset_y + 40))

def main():
    pygame.init()
    screen = pygame.display.set_mode((SCREEN_WIDTH * 3 + 200, SCREEN_HEIGHT))
    pygame.display.set_caption("Tetris for Three")

    tetris_games = [Tetris(1), Tetris(2), Tetris(3)]
    player_scores = [0, 0, 0]  # Keep track of individual scores
    game_over_flags = [False, False, False]

    clock = pygame.time.Clock()

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                for i, tetris in enumerate(tetris_games):
                    if not tetris.is_game_over():
                        if event.key == PLAYER_CONTROLS[i+1]['left']:
                            tetris.move_left()
                        elif event.key == PLAYER_CONTROLS[i+1]['right']:
                            tetris.move_right()
                        elif event.key == PLAYER_CONTROLS[i+1]['rotate']:
                            tetris.rotate()
                        elif event.key == PLAYER_CONTROLS[i+1]['drop']:
                            tetris.hard_drop()

        screen.fill(BLACK)

        # Update and draw each Tetris game
        for i, tetris in enumerate(tetris_games):
            if not tetris.is_game_over():
                tetris.drop()
                player_scores[i] = tetris.get_score()
            else:
                game_over_flags[i] = True

            offset_x = i * (SCREEN_WIDTH + 50)
            offset_y = 0

            draw_grid(screen, tetris.get_grid(), offset_x, offset_y)
            draw_piece(screen, tetris.get_current_piece(), offset_x, offset_y)
            draw_score(screen, tetris.get_score(), tetris.get_level(), offset_x, SCREEN_HEIGHT, i + 1)

            # Draw next piece
            next_piece_offset_x = offset_x + GRID_WIDTH * BLOCK_SIZE + 10
            next_piece_offset_y = 50
            draw_next_piece(screen, tetris.get_next_piece(), next_piece_offset_x, next_piece_offset_y)

            if tetris.is_game_over():
                font = pygame.font.Font(None, 72)
                game_over_text = font.render("Game Over", True, WHITE)
                text_rect = game_over_text.get_rect(center=(offset_x + SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
                screen.blit(game_over_text, text_rect)

        # Calculate and display combined score (example: average)
        if all(game_over_flags):
            total_score = sum(player_scores)
            average_score = total_score / 3 if total_score > 0 else 0
            font = pygame.font.Font(None, 48)
            combined_score_text = font.render(f"Combined Score: {average_score:.2f}", True, WHITE)
            text_rect = combined_score_text.get_rect(center=(SCREEN_WIDTH * 1.5, SCREEN_HEIGHT - 100))
            screen.blit(combined_score_text, text_rect)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()

if __name__ == "__main__":
    main()

