import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * CELL_SIZE * 3  # Triple width for three players
SCREEN_HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)

COLORS = [GRAY, RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]],  # T
]

class Tetromino:
    def __init__(self, x, y, shape):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = random.choice(COLORS)
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j]:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]
        self.score = 0
        self.lines_cleared = 0

    def is_valid_move(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            if x < 0 or x >= self.width or y >= self.height:
                return False
            if y >= 0 and self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_to_clear = []
        for i in range(self.height):
            if all(self.grid[i]):
                lines_to_clear.append(i)

        for line in lines_to_clear:
            del self.grid[line]
            self.grid.insert(0, [0] * self.width)

        num_lines = len(lines_to_clear)
        if num_lines > 0:
            self.lines_cleared += num_lines
            if num_lines == 1:
                self.score += 40
            elif num_lines == 2:
                self.score += 100
            elif num_lines == 3:
                self.score += 300
            elif num_lines == 4:
                self.score += 1200

class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.game_over = False
        self.grid_x_offset = grid_x_offset

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape)

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        self.next_tetromino = self.create_tetromino()

        if not self.grid.is_valid_move(self.current_tetromino):
            self.game_over = True
            return False
        return True

    def move_left(self):
        if self.current_tetromino:
            self.current_tetromino.x -= 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x += 1

    def move_right(self):
        if self.current_tetromino:
            self.current_tetromino.x += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= 1

    def move_down(self):
        if self.current_tetromino:
            self.current_tetromino.y += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.grid.place_tetromino(self.current_tetromino)
                self.grid.clear_lines()
                return self.new_tetromino()
            return True
        return False

    def rotate(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape  # Revert rotation

    def hard_drop(self):
        if self.current_tetromino:
            while self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y += 1
            self.current_tetromino.y -= 1
            self.grid.place_tetromino(self.current_tetromino)
            self.grid.clear_lines()
            return self.new_tetromino()
        return False

def draw_grid(screen, grid, x_offset):
    for y in range(grid.height):
        for x in range(grid.width):
            color = grid.grid[y][x]
            if color:
                pygame.draw.rect(screen, color, (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(screen, BLACK, (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)
            else:
                pygame.draw.rect(screen, WHITE, (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(screen, BLACK, (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

def draw_tetromino(screen, tetromino, x_offset):
    if tetromino:
        for x, y in tetromino.get_cells():
            pygame.draw.rect(screen, tetromino.color, (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
            pygame.draw.rect(screen, BLACK, (x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

def draw_next_tetromino(screen, tetromino, x_offset, y_offset):
    font = pygame.font.Font(None, 30)
    text = font.render("Next:", True, BLACK)
    screen.blit(text, (x_offset, y_offset - 30))

    if tetromino:
        for i in range(len(tetromino.shape)):
            for j in range(len(tetromino.shape[0])):
                if tetromino.shape[i][j]:
                    pygame.draw.rect(screen, tetromino.color, (x_offset + j * CELL_SIZE, y_offset + i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, BLACK, (x_offset + j * CELL_SIZE, y_offset + i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

def draw_score(screen, player, x_offset, y_offset):
    font = pygame.font.Font(None, 30)
    score_text = font.render(f"Player {player.player_id + 1} Score: {player.grid.score}", True, BLACK)
    lines_text = font.render(f"Lines: {player.grid.lines_cleared}", True, BLACK)
    screen.blit(score_text, (x_offset, y_offset))
    screen.blit(lines_text, (x_offset, y_offset + 30))

def main():
    pygame.init()
    screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
    pygame.display.set_caption("Tierce Tetris")
    clock = pygame.time.Clock()

    players = [
        Player(0, 0),
        Player(1, GRID_WIDTH * CELL_SIZE),
        Player(2, 2 * GRID_WIDTH * CELL_SIZE)
    ]

    for player in players:
        player.new_tetromino()

    fall_counter = 0
    fall_speed = 30

    running = True
    while running:
        screen.fill(WHITE)

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    players[0].move_left()
                if event.key == pygame.K_d:
                    players[0].move_right()
                if event.key == pygame.K_s:
                    players[0].move_down()
                if event.key == pygame.K_w:
                    players[0].rotate()
                if event.key == pygame.K_SPACE:
                    players[0].hard_drop()

                if event.key == pygame.K_j:
                    players[1].move_left()
                if event.key == pygame.K_l:
                    players[1].move_right()
                if event.key == pygame.K_k:
                    players[1].move_down()
                if event.key == pygame.K_i:
                    players[1].rotate()
                if event.key == pygame.K_o:
                    players[1].hard_drop()

                if event.key == pygame.K_LEFT:
                    players[2].move_left()
                if event.key == pygame.K_RIGHT:
                    players[2].move_right()
                if event.key == pygame.K_DOWN:
                    players[2].move_down()
                if event.key == pygame.K_UP:
                    players[2].rotate()
                if event.key == pygame.K_SLASH:
                    players[2].hard_drop()

        fall_counter += 1
        for player in players:
            if not player.game_over:
                if fall_counter >= fall_speed:
                    if not player.move_down():
                        player.game_over = True
        if fall_counter >= fall_speed:
            fall_counter = 0

        for player in players:
            draw_grid(screen, player.grid, player.grid_x_offset)
            draw_tetromino(screen, player.current_tetromino, player.grid_x_offset)
            draw_next_tetromino(screen, player.next_tetromino, player.grid_x_offset + GRID_WIDTH * CELL_SIZE + 20, 50)
            draw_score(screen, player, player.grid_x_offset, SCREEN_HEIGHT - 60)

            if player.game_over:
                font = pygame.font.Font(None, 50)
                text = font.render(f"Player {player.player_id + 1} Game Over!", True, RED)
                text_rect = text.get_rect(center=(player.grid_x_offset + GRID_WIDTH * CELL_SIZE // 2, SCREEN_HEIGHT // 2))
                screen.blit(text, text_rect)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()

if __name__ == "__main__":
    main()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * CELL_SIZE * 3  # Triple width for 3 players
SCREEN_HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [(0, 255, 255), (0, 0, 255), (255, 127, 0), (255, 255, 0), (0, 255, 0), (255, 0, 0), (178, 58, 238)]

class Piece:
    SHAPES = [
        [[1, 1, 1, 1]],  # I
        [[1, 1], [1, 1]],  # O
        [[0, 1, 1], [1, 1, 0]],  # Z
        [[1, 1, 0], [0, 1, 1]],  # S
        [[1, 0, 0], [1, 1, 1]],  # L
        [[0, 0, 1], [1, 1, 1]],  # J
        [[0, 1, 0], [1, 1, 1]]   # T
    ]

    def __init__(self, x, y, shape=None):
        self.x = x
        self.y = y
        if shape is None:
            self.shape = random.choice(self.SHAPES)
        else:
            self.shape = shape
        self.color = COLORS[self.SHAPES.index(self.shape)]

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]
        self.score = 0
        self.lines_cleared = 0

    def is_valid_move(self, piece, x, y):
        for row_index, row in enumerate(piece.shape):
            for col_index, cell in enumerate(row):
                if cell:
                    grid_x = x + col_index
                    grid_y = y + row_index
                    if (grid_x < 0 or grid_x >= self.width or
                        grid_y >= self.height or
                        (grid_y >= 0 and self.grid[grid_y][grid_x] != 0)):
                        return False
        return True

    def place_piece(self, piece):
        for row_index, row in enumerate(piece.shape):
            for col_index, cell in enumerate(row):
                if cell:
                    self.grid[piece.y + row_index][piece.x + col_index] = piece.color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = [i for i, row in enumerate(self.grid) if all(row)]
        for row_index in full_rows:
            del self.grid[row_index]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1

        if lines_cleared > 0:
            self.score += self.calculate_score(lines_cleared)
            self.lines_cleared += lines_cleared
        return lines_cleared

    def calculate_score(self, lines_cleared):
        if lines_cleared == 1:
            return 40
        elif lines_cleared == 2:
            return 100
        elif lines_cleared == 3:
            return 300
        elif lines_cleared == 4:
            return 1200
        return 0

    def is_game_over(self):
        return any(self.grid[0])

class Player:
    def __init__(self, player_id, grid_width, grid_height):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.current_piece = None
        self.next_piece = self.create_piece()
        self.game_over = False
        self.contribution = 0 # How much this player contributed to the overall score

    def create_piece(self):
        return Piece(self.grid.width // 2 - 2, 0)

    def new_piece(self):
        self.current_piece = self.next_piece
        self.current_piece.x = self.grid.width // 2 - 2
        self.current_piece.y = 0
        self.next_piece = self.create_piece()

        if not self.grid.is_valid_move(self.current_piece, self.current_piece.x, self.current_piece.y):
            self.game_over = True
            return False
        return True

    def move_piece_down(self):
        if self.current_piece:
            if self.grid.is_valid_move(self.current_piece, self.current_piece.x, self.current_piece.y + 1):
                self.current_piece.y += 1
            else:
                self.grid.place_piece(self.current_piece)
                lines_cleared = self.grid.clear_lines()
                self.contribution += self.grid.calculate_score(lines_cleared) # Update contribution
                if not self.new_piece():
                    return False
        return True

    def move_piece_sideways(self, direction):
        if self.current_piece:
            new_x = self.current_piece.x + direction
            if self.grid.is_valid_move(self.current_piece, new_x, self.current_piece.y):
                self.current_piece.x = new_x

    def rotate_piece(self):
        if self.current_piece:
            original_shape = [list(row) for row in self.current_piece.shape]
            self.current_piece.rotate()
            if not self.grid.is_valid_move(self.current_piece, self.current_piece.x, self.current_piece.y):
                self.current_piece.shape = original_shape # Revert rotation

    def drop_piece(self):
        if self.current_piece:
            while self.grid.is_valid_move(self.current_piece, self.current_piece.x, self.current_piece.y + 1):
                self.current_piece.y += 1
            self.grid.place_piece(self.current_piece)
            lines_cleared = self.grid.clear_lines()
            self.contribution += self.grid.calculate_score(lines_cleared) # Update contribution
            if not self.new_piece():
                return False
        return True

class Game:
    def __init__(self, num_players=3):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tierce Tetris")
        self.clock = pygame.time.Clock()
        self.num_players = num_players
        self.players = [Player(i, GRID_WIDTH, GRID_HEIGHT) for i in range(num_players)]
        self.font = pygame.font.Font(None, 36)
        self.game_over = False
        self.overall_score = 0
        self.start_time = pygame.time.get_ticks()
        self.last_drop_time = [pygame.time.get_ticks() for _ in range(num_players)]
        self.drop_speed = 750 # Milliseconds

        for player in self.players:
            player.new_piece()

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.players[0].move_piece_sideways(-1)
                elif event.key == pygame.K_RIGHT:
                    self.players[0].move_piece_sideways(1)
                elif event.key == pygame.K_DOWN:
                    self.players[0].move_piece_down()
                elif event.key == pygame.K_UP:
                    self.players[0].rotate_piece()
                elif event.key == pygame.K_SPACE:
                    self.players[0].drop_piece()

                if event.key == pygame.K_a:
                    self.players[1].move_piece_sideways(-1)
                elif event.key == pygame.K_d:
                    self.players[1].move_piece_sideways(1)
                elif event.key == pygame.K_s:
                    self.players[1].move_piece_down()
                elif event.key == pygame.K_w:
                    self.players[1].rotate_piece()
                elif event.key == pygame.K_q:
                    self.players[1].drop_piece()

                if event.key == pygame.K_j:
                    self.players[2].move_piece_sideways(-1)
                elif event.key == pygame.K_l:
                    self.players[2].move_piece_sideways(1)
                elif event.key == pygame.K_k:
                    self.players[2].move_piece_down()
                elif event.key == pygame.K_i:
                    self.players[2].rotate_piece()
                elif event.key == pygame.K_u:
                    self.players[2].drop_piece()

    def update(self):
        if self.game_over:
            return

        for i, player in enumerate(self.players):
            if not player.game_over:
                current_time = pygame.time.get_ticks()
                if current_time - self.last_drop_time[i] > self.drop_speed:
                    if not player.move_piece_down():
                        player.game_over = True
                    self.last_drop_time[i] = current_time

        # Check if all players are game over
        if all(player.game_over for player in self.players):
            self.game_over = True
            self.calculate_overall_score()

    def calculate_overall_score(self):
        self.overall_score = sum(player.grid.score for player in self.players)

    def render(self):
        self.screen.fill(BLACK)

        for i, player in enumerate(self.players):
            self.draw_grid(player.grid, i * GRID_WIDTH * CELL_SIZE)
            self.draw_piece(player.current_piece, i * GRID_WIDTH * CELL_SIZE)
            self.draw_next_piece(player.next_piece, i * GRID_WIDTH * CELL_SIZE)
            self.draw_score(player, i * GRID_WIDTH * CELL_SIZE)

        if self.game_over:
            self.draw_game_over()

        pygame.display.flip()

    def draw_grid(self, grid, offset_x):
        for row_index, row in enumerate(grid.grid):
            for col_index, cell in enumerate(row):
                x = offset_x + col_index * CELL_SIZE
                y = row_index * CELL_SIZE
                rect = pygame.Rect(x, y, CELL_SIZE, CELL_SIZE)
                if cell:
                    pygame.draw.rect(self.screen, cell, rect)
                    pygame.draw.rect(self.screen, GRAY, rect, 1)
                else:
                    pygame.draw.rect(self.screen, BLACK, rect)
                    pygame.draw.rect(self.screen, GRAY, rect, 1)

    def draw_piece(self, piece, offset_x):
        if piece:
            for row_index, row in enumerate(piece.shape):
                for col_index, cell in enumerate(row):
                    if cell:
                        x = offset_x + (piece.x + col_index) * CELL_SIZE
                        y = (piece.y + row_index) * CELL_SIZE
                        rect = pygame.Rect(x, y, CELL_SIZE, CELL_SIZE)
                        pygame.draw.rect(self.screen, piece.color, rect)
                        pygame.draw.rect(self.screen, GRAY, rect, 1)

    def draw_next_piece(self, piece, offset_x):
         if piece:
            text_surface = self.font.render("Next Piece:", True, WHITE)
            self.screen.blit(text_surface, (offset_x, SCREEN_HEIGHT - 150))
            for row_index, row in enumerate(piece.shape):
                for col_index, cell in enumerate(row):
                    if cell:
                        x = offset_x + (col_index) * CELL_SIZE + 20
                        y = (row_index) * CELL_SIZE + SCREEN_HEIGHT - 100
                        rect = pygame.Rect(x, y, CELL_SIZE, CELL_SIZE)
                        pygame.draw.rect(self.screen, piece.color, rect)
                        pygame.draw.rect(self.screen, GRAY, rect, 1)

    def draw_score(self, player, offset_x):
        score_text = self.font.render(f"Score: {player.grid.score}", True, WHITE)
        lines_text = self.font.render(f"Lines: {player.grid.lines_cleared}", True, WHITE)
        contribution_text = self.font.render(f"Contribution: {player.contribution}", True, WHITE)
        self.screen.blit(score_text, (offset_x, 10))
        self.screen.blit(lines_text, (offset_x, 50))
        self.screen.blit(contribution_text, (offset_x, 90))

    def draw_game_over(self):
        game_over_text = self.font.render("Game Over!", True, WHITE)
        score_text = self.font.render(f"Overall Score: {self.overall_score}", True, WHITE)
        self.screen.blit(game_over_text, (SCREEN_WIDTH // 2 - 80, SCREEN_HEIGHT // 2 - 50))
        self.screen.blit(score_text, (SCREEN_WIDTH // 2 - 100, SCREEN_HEIGHT // 2))

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

