        self.current_tetromino.x += dx
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x -= dx
            return False
        return True

    def drop_tetromino(self):
        self.current_tetromino.y += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.y -= 1
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.lines_cleared += lines_cleared
            self.score += lines_cleared ** 2 * 100
            return False  # Tetromino has landed
        return True

    def rotate_tetromino(self):
        original_rotation = self.current_tetromino.rotation
        self.current_tetromino.rotate()
        self.current_tetromino.rotation = (self.current_tetromino.rotation + 1) % 4
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.rotation = original_rotation
            self.current_tetromino.shape = self.current_tetromino.get_rotated_shape(original_rotation)

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Ternary Tetris Collaboration")
        self.clock = pygame.time.Clock()
        self.players = [Player(i) for i in range(3)]
        self.game_over = False
        self.font = pygame.font.Font(None, 36)
        self.collaboration_score = 0
        self.player_contributions = [0, 0, 0]
        self.total_lines_cleared = 0
        self.game_tick = 0
        self.drop_speed = 30 #frames

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    self.players[0].move_tetromino(-1)
                if event.key == pygame.K_d:
                    self.players[0].move_tetromino(1)
                if event.key == pygame.K_w:
                    self.players[0].rotate_tetromino()
                if event.key == pygame.K_LEFT:
                    self.players[1].move_tetromino(-1)
                if event.key == pygame.K_RIGHT:
                    self.players[1].move_tetromino(1)
                if event.key == pygame.K_UP:
                    self.players[1].rotate_tetromino()
                if event.key == pygame.K_j:
                    self.players[2].move_tetromino(-1)
                if event.key == pygame.K_l:
                    self.players[2].move_tetromino(1)
                if event.key == pygame.K_i:
                    self.players[2].rotate_tetromino()

    def update(self):
        if self.game_over:
            return

        for player in self.players:
            if player.current_tetromino is None:
                if not player.new_tetromino():
                    self.game_over = True
                    return

        self.game_tick += 1
        if self.game_tick % self.drop_speed == 0:
            for player in self.players:
                if not player.drop_tetromino():
                    if not player.new_tetromino():
                        self.game_over = True
                        return

        self.calculate_collaboration_score()
        self.calculate_player_contributions()

    def calculate_collaboration_score(self):
        self.total_lines_cleared = sum(player.lines_cleared for player in self.players)
        self.collaboration_score = sum(player.score for player in self.players) + self.total_lines_cleared * 50

    def calculate_player_contributions(self):
        total_score = sum(player.score for player in self.players)
        if total_score > 0:
            for i, player in enumerate(self.players):
                self.player_contributions[i] = player.score / total_score
        else:
            self.player_contributions = [1/3, 1/3, 1/3] #default if no score

    def draw_grid(self, player, x_offset):
        for y in range(player.grid.height):
            for x in range(player.grid.width):
                color_index = player.grid.grid[y][x]
                color = COLORS[color_index]
                pygame.draw.rect(self.screen, color, (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(self.screen, COLORS[7], (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1) #white outline

        if player.current_tetromino:
            for x, y in player.current_tetromino.get_cells():
                pygame.draw.rect(self.screen, player.current_tetromino.color, (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(self.screen, COLORS[7], (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1) #white outline

    def draw_next_tetromino(self, player, x_offset, y_offset):
        text_surface = self.font.render(f"Next:", True, COLORS[7])
        self.screen.blit(text_surface, (x_offset, y_offset - 30))

        for row_index, row in enumerate(player.next_tetromino.shape):
            for col_index, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, player.next_tetromino.color, (x_offset + col_index * BLOCK_SIZE, y_offset + row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(self.screen, COLORS[7], (x_offset + col_index * BLOCK_SIZE, y_offset + row_index * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1) #white outline

    def draw_scoreboards(self):
        x_offset = GRID_WIDTH * BLOCK_SIZE
        y_offset = 20

        for i, player in enumerate(self.players):
            text_surface = self.font.render(f"Player {i+1}: {player.score}", True, COLORS[7])
            self.screen.blit(text_surface, (x_offset + 20, y_offset + i * 100))
            text_surface = self.font.render(f"Lines: {player.lines_cleared}", True, COLORS[7])
            self.screen.blit(text_surface, (x_offset + 20, y_offset + i * 100 + 30))
            self.draw_next_tetromino(player, x_offset + 20, y_offset + i * 100 + 70)

        text_surface = self.font.render(f"Collaboration Score: {self.collaboration_score}", True, COLORS[7])
        self.screen.blit(text_surface, (x_offset + 20, y_offset + 350))

        text_surface = self.font.render(f"Player Contributions:", True, COLORS[7])
        self.screen.blit(text_surface, (x_offset + 20, y_offset + 400))
        for i, contribution in enumerate(self.player_contributions):
            text_surface = self.font.render(f"Player {i+1}: {contribution:.2f}", True, COLORS[7])
            self.screen.blit(text_surface, (x_offset + 20, y_offset + 430 + i * 30))

    def draw(self):
        self.screen.fill(COLORS[0])  # Black background
        self.draw_grid(self.players[0], 0)
        self.draw_grid(self.players[1], GRID_WIDTH * BLOCK_SIZE // 3)
        self.draw_grid(self.players[2], 2 * GRID_WIDTH * BLOCK_SIZE // 3)
        self.draw_scoreboards()

        if self.game_over:
            text_surface = self.font.render("Game Over!", True, COLORS[7])
            text_rect = text_surface.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
            self.screen.blit(text_surface, text_rect)

        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

