import pygame
import random
import sys

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
PLAYER_COUNT = 3
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255), (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)]  # Black, Red, Green, Blue, Yellow, Magenta, Cyan, White
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 1, 0], [0, 1, 1]],  # S
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

    def get_cells(self):
        cells = []
        for i, row in enumerate(self.shape):
            for j, cell in enumerate(row):
                if cell:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= self.width or y >= self.height or self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino):
        for x, y in tetromino.get_cells():
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = [i for i, row in enumerate(self.grid) if all(cell != 0 for cell in row)]
        for row in full_rows:
            del self.grid[row]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.grid_x_offset = grid_x_offset
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[random.randint(1, len(COLORS) - 1)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino):
            return False # Game Over
        return True

    def move_tetromino(self, dx):
        self.current_tetromino.x += dx
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x -= dx
            return False
        return True

    def move_tetromino_down(self):
        self.current_tetromino.y += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.y -= 1
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.score += lines_cleared ** 2 * 100
            return False # Tetromino has landed
        return True

    def rotate_tetromino(self):
        original_shape = [list(row) for row in [list(r) for r in self.current_tetromino.shape]]
        self.current_tetromino.rotate()
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.shape = original_shape
            return False
        return True

class Game:
    def __init__(self):
        pygame.init()
        self.screen_width = GRID_WIDTH * CELL_SIZE * PLAYER_COUNT + 20 * (PLAYER_COUNT - 1) # Add spacing between grids
        self.screen_height = GRID_HEIGHT * CELL_SIZE
        self.screen = pygame.display.set_mode((self.screen_width, self.screen_height))
        pygame.display.set_caption("Ternion Tetris: Quisling Edition")
        self.clock = pygame.time.Clock()
        self.players = [Player(i, i * (GRID_WIDTH * CELL_SIZE + 20)) for i in range(PLAYER_COUNT)]
        self.game_over = [False] * PLAYER_COUNT
        self.fall_speed = 500 # milliseconds
        self.last_fall_time = [pygame.time.get_ticks()] * PLAYER_COUNT
        self.font = pygame.font.Font(None, 36)
        self.running = True
        self.fairness_contribution = [0] * PLAYER_COUNT

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                for i, player in enumerate(self.players):
                    if self.game_over[i]:
                        continue
                    if event.key == pygame.K_LEFT and i == 0:
                        player.move_tetromino(-1)
                    if event.key == pygame.K_RIGHT and i == 0:
                        player.move_tetromino(1)
                    if event.key == pygame.K_DOWN and i == 0:
                        player.move_tetromino_down()
                    if event.key == pygame.K_UP and i == 0:
                        player.rotate_tetromino()

                    if event.key == pygame.K_a and i == 1:
                        player.move_tetromino(-1)
                    if event.key == pygame.K_d and i == 1:
                        player.move_tetromino(1)
                    if event.key == pygame.K_s and i == 1:
                        player.move_tetromino_down()
                    if event.key == pygame.K_w and i == 1:
                        player.rotate_tetromino()

                    if event.key == pygame.K_j and i == 2:
                        player.move_tetromino(-1)
                    if event.key == pygame.K_l and i == 2:
                        player.move_tetromino(1)
                    if event.key == pygame.K_k and i == 2:
                        player.move_tetromino_down()
                    if event.key == pygame.K_i and i == 2:
                        player.rotate_tetromino()

    def update(self):
        for i, player in enumerate(self.players):
            if self.game_over[i]:
                continue

            if player.current_tetromino is None:
                if not player.spawn_tetromino():
                    self.game_over[i] = True
                    continue

            current_time = pygame.time.get_ticks()
            if current_time - self.last_fall_time[i] > self.fall_speed:
                if not player.move_tetromino_down():
                    player.current_tetromino = None
                self.last_fall_time[i] = current_time

        #Fairness Contribution Calculation
        total_score = sum(player.score for player in self.players)
        if total_score > 0:
            for i, player in enumerate(self.players):
                self.fairness_contribution[i] = player.score / total_score
        else:
            self.fairness_contribution = [1/PLAYER_COUNT] * PLAYER_COUNT #Equal contribution if no score

    def draw_grid(self, player):
        for y in range(player.grid.height):
            for x in range(player.grid.width):
                color = COLORS[player.grid.grid[y][x]]
                pygame.draw.rect(self.screen, color, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(self.screen, COLORS[7], (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1) # White outline

    def draw_tetromino(self, player):
        if player.current_tetromino:
            for x, y in player.current_tetromino.get_cells():
                pygame.draw.rect(self.screen, COLORS[player.current_tetromino.color], (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(self.screen, COLORS[7], (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1) # White outline

    def draw_next_tetromino(self, player):
        text_surface = self.font.render(f"Next:", True, COLORS[7])
        self.screen.blit(text_surface, (player.grid_x_offset, GRID_HEIGHT * CELL_SIZE + 10))

        next_tetromino = player.next_tetromino
        for i, row in enumerate(next_tetromino.shape):
            for j, cell in enumerate(row):
                if cell:
                    x = player.grid_x_offset + j * CELL_SIZE - (len(next_tetromino.shape[0]) // 2) * CELL_SIZE + GRID_WIDTH * CELL_SIZE // 2
                    y = GRID_HEIGHT * CELL_SIZE + 50 + i * CELL_SIZE - (len(next_tetromino.shape) // 2) * CELL_SIZE
                    pygame.draw.rect(self.screen, COLORS[next_tetromino.color], (x, y, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(self.screen, COLORS[7], (x, y, CELL_SIZE, CELL_SIZE), 1)

    def draw_score(self, player):
        text_surface = self.font.render(f"Score: {player.score}", True, COLORS[7])
        self.screen.blit(text_surface, (player.grid_x_offset, GRID_HEIGHT * CELL_SIZE + 150))

    def draw_fairness(self, player):
         text_surface = self.font.render(f"Contribution: {self.fairness_contribution[player.player_id]:.2f}", True, COLORS[7])
         self.screen.blit(text_surface, (player.grid_x_offset, GRID_HEIGHT * CELL_SIZE + 200))

    def draw_game_over(self, player):
        text_surface = self.font.render("Game Over!", True, COLORS[1])
        text_rect = text_surface.get_rect(center=(player.grid_x_offset + GRID_WIDTH * CELL_SIZE // 2, GRID_HEIGHT * CELL_SIZE // 2))
        self.screen.blit(text_surface, text_rect)

    def draw(self):
        self.screen.fill(COLORS[0]) # Black background

        for i, player in enumerate(self.players):
            self.draw_grid(player)
            self.draw_tetromino(player)
            self.draw_next_tetromino(player)
            self.draw_score(player)
            self.draw_fairness(player)
            if self.game_over[i]:
                self.draw_game_over(player)

        pygame.display.flip()

    def run(self):
