FPS = 30
PLAYER_COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255)]  # Red, Green, Blue
BACKGROUND_COLOR = (0, 0, 0)
GRID_COLOR = (50, 50, 50)
TEXT_COLOR = (255, 255, 255)

# Tetromino shapes (7 standard Tetris pieces)
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

# Game state
class GameState:
    def __init__(self, player_id):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_piece = None
        self.current_x = 0
        self.current_y = 0
        self.score = 0
        self.player_id = player_id
        self.game_over = False
        self.next_piece = self.new_piece()

    def new_piece(self):
        return random.choice(SHAPES)

    def spawn_piece(self):
        self.current_piece = self.next_piece
        self.next_piece = self.new_piece()
        self.current_x = GRID_WIDTH // 2 - len(self.current_piece[0]) // 2
        self.current_y = 0
        if not self.is_valid_position(self.current_piece, self.current_x, self.current_y):
            self.game_over = True

    def rotate_piece(self):
        rotated_piece = list(zip(*self.current_piece[::-1]))
        if self.is_valid_position(rotated_piece, self.current_x, self.current_y):
            self.current_piece = rotated_piece

    def is_valid_position(self, piece, x, y):
        for row in range(len(piece)):
            for col in range(len(piece[row])):
                if piece[row][col]:
                    grid_x = x + col
                    grid_y = y + row
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT:
                        return False
                    if grid_y >= 0 and self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def move(self, dx):
        if self.is_valid_position(self.current_piece, self.current_x + dx, self.current_y):
            self.current_x += dx

    def drop(self):
        while self.is_valid_position(self.current_piece, self.current_x, self.current_y + 1):
            self.current_y += 1
        self.lock_piece()

    def lock_piece(self):
        for row in range(len(self.current_piece)):
            for col in range(len(self.current_piece[row])):
                if self.current_piece[row][col]:
                    self.grid[self.current_y + row][self.current_x + col] = self.player_id + 1  # Use player ID for color

        self.clear_lines()
        self.spawn_piece()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1

        if lines_cleared == 1:
            self.score += 100
        elif lines_cleared == 2:
            self.score += 300
        elif lines_cleared == 3:
            self.score += 500
        elif lines_cleared == 4:
            self.score += 800

