                    pygame.draw.rect(screen, GRAY, (MARGIN + (current_piece_x + j) * BLOCK_SIZE, MARGIN + (current_piece_y + i) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_scores():
