def draw_game_over():
    font = pygame.font.Font(None, 72)
    text = font.render("Game Over!", True, RED)
    text_rect = text.get_rect(center=(TOTAL_WIDTH // 2, TOTAL_HEIGHT // 2))
    screen.blit(text, text_rect)

def drop_piece():
    global current_piece, current_piece_x, current_piece_y, game_over
    if is_valid_move(current_piece, current_piece_x, current_piece_y + 1):
        current_piece_y += 1
    else:
        place_piece()
        new_piece()
        if not is_valid_move(current_piece, current_piece_x, current_piece_y):
            game_over = True

new_piece()

# Game loop
