import pygame
import random
import sys

# Initialize Pygame
pygame.init()

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = GRID_WIDTH * BLOCK_SIZE
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
MARGIN = 50
TOTAL_WIDTH = WIDTH + 2 * MARGIN
TOTAL_HEIGHT = HEIGHT + 2 * MARGIN
FPS = 30

# Colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)

COLORS = [GRAY, RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA, ORANGE]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[0, 1, 0], [1, 1, 1]],  # T
]

# Player controls
PLAYER_CONTROLS = {
    1: {'left': pygame.K_a, 'right': pygame.K_d, 'rotate': pygame.K_s, 'drop': pygame.K_w},
    2: {'left': pygame.K_j, 'right': pygame.K_l, 'rotate': pygame.K_k, 'drop': pygame.K_i},
    3: {'left': pygame.K_LEFT, 'right': pygame.K_RIGHT, 'rotate': pygame.K_UP, 'drop': pygame.K_DOWN}
}

# Initialize screen
screen = pygame.display.set_mode((TOTAL_WIDTH, TOTAL_HEIGHT))
pygame.display.set_caption("Collaborative Tetris")

# Font
font = pygame.font.Font(None, 30)

class Tetromino:
    def __init__(self, x, y, shape, player_id):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = COLORS[random.randint(1, len(COLORS) - 1)]
        self.rotation = 0
        self.player_id = player_id

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        return rotated_shape

    def get_rotated_shape(self):
        rotated_shape = self.shape
        for _ in range(self.rotation % 4):
            rotated_shape = list(zip(*rotated_shape[::-1]))
        return rotated_shape

    def collides(self, grid):
        shape = self.get_rotated_shape()
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    x = self.x + j
                    y = self.y + i
                    if x < 0 or x >= GRID_WIDTH or y >= GRID_HEIGHT or grid[y][x] != 0:
                        return True
        return False

    def draw(self, surface):
        shape = self.get_rotated_shape()
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    pygame.draw.rect(surface, self.color,
                                     (MARGIN + (self.x + j) * BLOCK_SIZE, MARGIN + (self.y + i) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(surface, BLACK,
                                     (MARGIN + (self.x + j) * BLOCK_SIZE, MARGIN + (self.y + i) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

class Game:
    def __init__(self, num_players=3):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = None
        self.next_tetromino = None
        self.game_over = False
        self.scores = {i: 0 for i in range(1, num_players + 1)}
        self.player_contributions = {i: 0 for i in range(1, num_players + 1)}
        self.num_players = num_players
        self.current_player = 1
        self.drop_speed = 1
        self.frame_count = 0
        self.level = 1
        self.lines_cleared = 0
        self.next_piece()

    def new_tetromino(self, player_id):
        shape = random.choice(SHAPES)
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, player_id)

    def next_piece(self):
        if self.next_tetromino is None:
            self.current_tetromino = self.new_tetromino(self.current_player)
            self.next_tetromino = self.new_tetromino(random.randint(1, self.num_players))
        else:
            self.current_tetromino = self.next_tetromino
            self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
            self.current_tetromino.y = 0
            self.current_tetromino.player_id = self.current_player
            self.next_tetromino = self.new_tetromino(random.randint(1, self.num_players))

        if self.current_tetromino.collides(self.grid):
            self.game_over = True

    def drop(self):
        if not self.game_over:
            self.current_tetromino.y += 1
            if self.current_tetromino.collides(self.grid):
                self.current_tetromino.y -= 1
                self.lock_tetromino()

    def lock_tetromino(self):
        shape = self.current_tetromino.get_rotated_shape()
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    x = self.current_tetromino.x + j
                    y = self.current_tetromino.y + i
                    self.grid[y][x] = self.current_tetromino.color

        self.next_piece()
        lines_cleared = self.clear_lines()
        self.scores[self.current_tetromino.player_id] += lines_cleared ** 2 * 100
        self.player_contributions[self.current_tetromino.player_id] += 1
        self.lines_cleared += lines_cleared
        self.level = self.lines_cleared // 10 + 1
        self.drop_speed = self.level

        self.current_player = random.randint(1, self.num_players)

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                full_rows.append(i)

        for row in full_rows:
            del self.grid[row]
            self.grid.insert(0, [0] * GRID_WIDTH)
            lines_cleared += 1
        return lines_cleared

    def move_sideways(self, direction):
        if not self.game_over:
            self.current_tetromino.x += direction
            if self.current_tetromino.collides(self.grid):
                self.current_tetromino.x -= direction

    def rotate_tetromino(self):
        if not self.game_over:
            original_rotation = self.current_tetromino.rotation
            self.current_tetromino.rotation += 1
            if self.current_tetromino.collides(self.grid):
                self.current_tetromino.rotation = original_rotation

    def draw_grid(self, surface):
        for i in range(GRID_HEIGHT):
            for j in range(GRID_WIDTH):
                if self.grid[i][j] != 0:
                    pygame.draw.rect(surface, self.grid[i][j],
                                     (MARGIN + j * BLOCK_SIZE, MARGIN + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(surface, BLACK,
                                     (MARGIN + j * BLOCK_SIZE, MARGIN + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(surface, WHITE,
                                     (MARGIN + j * BLOCK_SIZE, MARGIN + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(surface, GRAY,
                                     (MARGIN + j * BLOCK_SIZE, MARGIN + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_next_tetromino(self, surface):
        next_shape = self.next_tetromino.shape
        next_color = self.next_tetromino.color
        text_surface = font.render(f"Next Piece (Player {self.next_tetromino.player_id})", True, WHITE)
        surface.blit(text_surface, (WIDTH + MARGIN + 10, MARGIN))

        for i in range(len(next_shape)):
            for j in range(len(next_shape[0])):
                if next_shape[i][j]:
                    pygame.draw.rect(surface, next_color,
                                     (WIDTH + MARGIN + 10 + j * BLOCK_SIZE, MARGIN + 40 + i * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(surface, BLACK,
                                     (WIDTH + MARGIN + 10 + j * BLOCK_SIZE, MARGIN + 40 + i * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_scores(self, surface):
        y_offset = MARGIN
        for player_id, score in self.scores.items():
            text_surface = font.render(f"Player {player_id}: {score}", True, WHITE)
            surface.blit(text_surface, (10, y_offset))
            y_offset += 30

    def draw_contributions(self, surface):
        y_offset = MARGIN
        for player_id, contribution in self.player_contributions.items():
             text_surface = font.render(f"Player {player_id} blocks: {contribution}", True, WHITE)
             surface.blit(text_surface, (10, y_offset + 100))
             y_offset += 30

    def draw_current_player(self, surface):
        text_surface = font.render(f"Current Player: {self.current_player}", True, WHITE)
        surface.blit(text_surface, (WIDTH + MARGIN + 10, HEIGHT - 50))

    def draw_level(self, surface):
        text_surface = font.render(f"Level: {self.level}", True, WHITE)
        surface.blit(text_surface, (WIDTH + MARGIN + 10, HEIGHT - 100))

    def run(self):
        clock = pygame.time.Clock()
        while not self.game_over:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()
                if event.type == pygame.KEYDOWN:
                    for player_id in range(1, self.num_players + 1):
                        if self.current_player == player_id:
                            if event.key == PLAYER_CONTROLS[player_id]['left']:
                                self.move_sideways(-1)
                            if event.key == PLAYER_CONTROLS[player_id]['right']:
                                self.move_sideways(1)
                            if event.key == PLAYER_CONTROLS[player_id]['rotate']:
                                self.rotate_tetromino()
                            if event.key == PLAYER_CONTROLS[player_id]['drop']:
                                while not self.current_tetromino.collides(self.grid):
                                    self.current_tetromino.y += 1
                                self.current_tetromino.y -= 1
                                self.lock_tetromino()

            self.frame_count += 1
            if self.frame_count >= FPS // self.drop_speed:
                self.drop()
                self.frame_count = 0

            # Draw everything
            screen.fill(BLACK)
            self.draw_grid(screen)
            self.current_tetromino.draw(screen)
            self.draw_next_tetromino(screen)
            self.draw_scores(screen)
            self.draw_contributions(screen)
            self.draw_current_player(screen)
            self.draw_level(screen)

            pygame.display.flip()
            clock.tick(FPS)

        # Game over screen
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()

            screen.fill(BLACK)
            game_over_text = font.render("Game Over!", True, RED)
            screen.blit(game_over_text, (TOTAL_WIDTH // 2 - 50, TOTAL_HEIGHT // 2 - 50))
            final_scores_text = font.render(f"Final Scores: {self.scores}", True, WHITE)
            screen.blit(final_scores_text, (TOTAL_WIDTH // 2 - 100, TOTAL_HEIGHT // 2))
            pygame.display.flip()

if __name__ == '__main__':
    game = Game(num_players=3)
    game.run()

