                                     (WIDTH + MARGIN + 10 + j * BLOCK_SIZE, MARGIN + 40 + i * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(surface, BLACK,
                                     (WIDTH + MARGIN + 10 + j * BLOCK_SIZE, MARGIN + 40 + i * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_scores(self, surface):
        y_offset = MARGIN
        for player_id, score in self.scores.items():
            text_surface = font.render(f"Player {player_id}: {score}", True, WHITE)
            surface.blit(text_surface, (10, y_offset))
            y_offset += 30

    def draw_contributions(self, surface):
        y_offset = MARGIN
        for player_id, contribution in self.player_contributions.items():
             text_surface = font.render(f"Player {player_id} blocks: {contribution}", True, WHITE)
             surface.blit(text_surface, (10, y_offset + 100))
             y_offset += 30

    def draw_current_player(self, surface):
        text_surface = font.render(f"Current Player: {self.current_player}", True, WHITE)
        surface.blit(text_surface, (WIDTH + MARGIN + 10, HEIGHT - 50))

    def draw_level(self, surface):
        text_surface = font.render(f"Level: {self.level}", True, WHITE)
        surface.blit(text_surface, (WIDTH + MARGIN + 10, HEIGHT - 100))

    def run(self):
        clock = pygame.time.Clock()
        while not self.game_over:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()
                if event.type == pygame.KEYDOWN:
                    for player_id in range(1, self.num_players + 1):
                        if self.current_player == player_id:
                            if event.key == PLAYER_CONTROLS[player_id]['left']:
                                self.move_sideways(-1)
                            if event.key == PLAYER_CONTROLS[player_id]['right']:
                                self.move_sideways(1)
                            if event.key == PLAYER_CONTROLS[player_id]['rotate']:
                                self.rotate_tetromino()
                            if event.key == PLAYER_CONTROLS[player_id]['drop']:
                                while not self.current_tetromino.collides(self.grid):
                                    self.current_tetromino.y += 1
                                self.current_tetromino.y -= 1
                                self.lock_tetromino()

            self.frame_count += 1
            if self.frame_count >= FPS // self.drop_speed:
                self.drop()
                self.frame_count = 0

            # Draw everything
            screen.fill(BLACK)
            self.draw_grid(screen)
            self.current_tetromino.draw(screen)
            self.draw_next_tetromino(screen)
            self.draw_scores(screen)
            self.draw_contributions(screen)
            self.draw_current_player(screen)
            self.draw_level(screen)

            pygame.display.flip()
            clock.tick(FPS)

        # Game over screen
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()

            screen.fill(BLACK)
            game_over_text = font.render("Game Over!", True, RED)
            screen.blit(game_over_text, (TOTAL_WIDTH // 2 - 50, TOTAL_HEIGHT // 2 - 50))
            final_scores_text = font.render(f"Final Scores: {self.scores}", True, WHITE)
            screen.blit(final_scores_text, (TOTAL_WIDTH // 2 - 100, TOTAL_HEIGHT // 2))
            pygame.display.flip()

if __name__ == '__main__':
    game = Game(num_players=3)
    game.run()

