        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

    def get_rotated_shape(self, rotation):
        temp_shape = self.shape
        for _ in range(rotation):
            temp_shape = list(zip(*temp_shape[::-1]))
            temp_shape = [list(row) for row in temp_shape]
        return temp_shape

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)

class Player:
    def __init__(self, player_id, x_offset):
        self.player_id = player_id
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.score = 0
        self.x_offset = x_offset
        self.current_tetromino = None
        self.next_tetromino = self.new_tetromino()
        self.game_over = False
        self.lines_cleared = 0

    def new_tetromino(self):
        shape = random.choice(TETROMINOS)
        color = PLAYER_COLORS[self.player_id]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

