        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.new_tetromino()
        if not self.is_valid_position(self.current_tetromino.x, self.current_tetromino.y, self.current_tetromino.shape):
            self.game_over = True

    def move_left(self):
        if self.current_tetromino and self.is_valid_position(self.current_tetromino.x - 1, self.current_tetromino.y, self.current_tetromino.shape):
            self.current_tetromino.x -= 1

    def move_right(self):
        if self.current_tetromino and self.is_valid_position(self.current_tetromino.x + 1, self.current_tetromino.y, self.current_tetromino.shape):
            self.current_tetromino.x += 1

    def move_down(self):
        if self.current_tetromino:
            if self.is_valid_position(self.current_tetromino.x, self.current_tetromino.y + 1, self.current_tetromino.shape):
                self.current_tetromino.y += 1
            else:
                self.lock_tetromino()

