        if self.current_tetromino:
            rotated_shape = list(zip(*self.current_tetromino.shape[::-1]))
            rotated_shape = [list(row) for row in rotated_shape]
            if self.is_valid_position(self.current_tetromino.x, self.current_tetromino.y, rotated_shape):
                self.current_tetromino.shape = rotated_shape

    def is_valid_position(self, x, y, shape):
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    grid_x = x + j
                    grid_y = y + i
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT or self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def lock_tetromino(self):
        for i in range(len(self.current_tetromino.shape)):
            for j in range(len(self.current_tetromino.shape[0])):
                if self.current_tetromino.shape[i][j]:
                    self.grid[self.current_tetromino.y + i][self.current_tetromino.x + j] = self.current_tetromino.color
        self.clear_lines()
        self.spawn_tetromino()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                lines_cleared += 1
                del self.grid[i]
                self.grid.insert(0, [0] * GRID_WIDTH)

        if lines_cleared > 0:
            self.lines_cleared += lines_cleared
            if lines_cleared == 1:
                self.score += 100
            elif lines_cleared == 2:
                self.score += 300
            elif lines_cleared == 3:
                self.score += 500
            else:
                self.score += 800

