        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                if self.grid[y][x]:
                    pygame.draw.rect(screen, self.grid[y][x],
                                     (self.x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, GRID_COLOR,
                                     (self.x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)
                else:
                    pygame.draw.rect(screen, BACKGROUND_COLOR,
                                     (self.x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, GRID_COLOR,
                                     (self.x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_tetromino(self, screen):
        if self.current_tetromino:
            for i in range(len(self.current_tetromino.shape)):
                for j in range(len(self.current_tetromino.shape[0])):
                    if self.current_tetromino.shape[i][j]:
