                if next_tetromino.shape[i][j]:
                    pygame.draw.rect(screen, next_tetromino.color,
                                     (start_x + j * CELL_SIZE, start_y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, GRID_COLOR,
                                     (start_x + j * CELL_SIZE, start_y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_score(self, screen):
        font = pygame.font.Font(None, 30)
        text = font.render(f"Score: {self.score}", True, TEXT_COLOR)
        screen.blit(text, (self.x_offset, HEIGHT + 150))

    def draw_lines_cleared(self, screen):
        font = pygame.font.Font(None, 30)
        text = font.render(f"Lines: {self.lines_cleared}", True, TEXT_COLOR)
        screen.blit(text, (self.x_offset, HEIGHT + 190))

