    for player in players:
        player.spawn_tetromino()

    clock = pygame.time.Clock()
    fall_speed = 30
    fall_counter = 0

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    player1.move_left()
                if event.key == pygame.K_d:
                    player1.move_right()
                if event.key == pygame.K_s:
                    player1.move_down()
                if event.key == pygame.K_q:
                    player1.rotate_tetromino()

                if event.key == pygame.K_j:
                    player2.move_left()
                if event.key == pygame.K_l:
                    player2.move_right()
                if event.key == pygame.K_k:
                    player2.move_down()
                if event.key == pygame.K_u:
                    player2.rotate_tetromino()

                if event.key == pygame.K_LEFT:
                    player3.move_left()
                if event.key == pygame.K_RIGHT:
                    player3.move_right()
                if event.key == pygame.K_DOWN:
                    player3.move_down()
                if event.key == pygame.K_UP:
                    player3.rotate_tetromino()

        fall_counter += 1
        for player in players:
            if not player.game_over:
                if fall_counter >= fall_speed:
                    player.move_down()
                    fall_counter = 0

        screen.fill(BACKGROUND_COLOR)

        for player in players:
            player.draw_grid(screen)
            player.draw_tetromino(screen)
            player.draw_next_tetromino(screen)
            player.draw_score(screen)
            player.draw_lines_cleared(screen)

            if player.game_over:
                font = pygame.font.Font(None, 50)
                text = font.render("Game Over!", True, TEXT_COLOR)
                text_rect = text.get_rect(center=(player.x_offset + GRID_WIDTH * CELL_SIZE // 2, HEIGHT // 2))
                screen.blit(text, text_rect)

        # Calculate and display total score and contribution
        total_score = sum(player.score for player in players)
        if total_score > 0:
            font = pygame.font.Font(None, 30)
            total_score_text = font.render(f"Total Score: {total_score}", True, TEXT_COLOR)
            screen.blit(total_score_text, (WIDTH // 2 - total_score_text.get_width() // 2, HEIGHT + 10))

            for i, player in enumerate(players):
                contribution = (player.score / total_score) * 100
                contribution_text = font.render(f"Player {i+1} Contribution: {contribution:.2f}%", True, PLAYER_COLORS[i])
                screen.blit(contribution_text, (WIDTH // 2 - contribution_text.get_width() // 2, HEIGHT + 50 + i * 30))
        else:
            font = pygame.font.Font(None, 30)
            total_score_text = font.render(f"Total Score: {total_score}", True, TEXT_COLOR)
            screen.blit(total_score_text, (WIDTH // 2 - total_score_text.get_width() // 2, HEIGHT + 10))
            no_score_text = font.render("No score yet!", True, TEXT_COLOR)
            screen.blit(no_score_text, (WIDTH // 2 - no_score_text.get_width() // 2, HEIGHT + 50))

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()

if __name__ == "__main__":
    main()

