class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, shape, x, y):
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    grid_x = x + j
                    grid_y = y + i
                    if (grid_x < 0 or grid_x >= self.width or
                        grid_y >= self.height or
                        self.grid[grid_y][grid_x] != 0):
                        return False
        return True

    def place_shape(self, shape, x, y, color):
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen, offset_x):
        for y in range(self.height):
            for x in range(self.width):
                color = COLORS[self.grid[y][x]]
                pygame.draw.rect(screen, color,
                                 (offset_x + x * CELL_SIZE, y * CELL_SIZE,
                                  CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(screen, (128, 128, 128),
                                 (offset_x + x * CELL_SIZE, y * CELL_SIZE,
                                  CELL_SIZE, CELL_SIZE), 1)

