            if not game_over[i] and drop_timer > drop_interval:
                game_over[i] = player.update()

        if drop_timer > drop_interval:
            drop_timer = 0

        # Draw everything
        screen.fill((0, 0, 0))
        for i, player in enumerate(players):
            player.draw(screen, i * GRID_WIDTH * CELL_SIZE)

