            text = font.render(f"Player {i+1}: {player.score}", True, (255, 255, 255))
            screen.blit(text, (i * GRID_WIDTH * CELL_SIZE, HEIGHT - 50))

        total_score = sum(player.score for player in players)
        contributions = calculate_contributions(players, total_score)

