import pygame
import random

# Constants
WIDTH, HEIGHT = 800, 600
GRID_WIDTH, GRID_HEIGHT = 10, 20
CELL_SIZE = 30
FPS = 30
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255), (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)] # Black, Red, Green, Blue, Yellow, Magenta, Cyan, White

# Tetromino shapes (7 shapes, each with 4 rotations)
TETROMINOS = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 1, 0], [0, 1, 1]],  # S
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]]   # T
]

def rotate(shape):
    return [[shape[y][x] for y in range(len(shape))] for x in range(len(shape[0]) - 1, -1, -1)]

class Tetris:
    def __init__(self, player_id):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_piece = self.new_piece()
        self.piece_x = GRID_WIDTH // 2 - len(self.current_piece[0]) // 2
        self.piece_y = 0
        self.score = 0
        self.game_over = False
        self.player_id = player_id
        self.color = random.randint(1, len(COLORS) - 1) # Assign a unique color to each player

    def new_piece(self):
        shape = random.choice(TETROMINOS)
        return shape

    def valid_move(self, shape, x, y):
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    grid_x = x + j
                    grid_y = y + i
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT or self.grid[grid_y][grid_x]:
                        return False
        return True

    def lock_piece(self):
        for i in range(len(self.current_piece)):
            for j in range(len(self.current_piece[0])):
                if self.current_piece[i][j]:
                    self.grid[self.piece_y + i][self.piece_x + j] = self.color

        cleared_lines = self.clear_lines()
        self.score += cleared_lines ** 2 * 100  # Simple scoring system
        self.current_piece = self.new_piece()
        self.piece_x = GRID_WIDTH // 2 - len(self.current_piece[0]) // 2
        self.piece_y = 0
        if not self.valid_move(self.current_piece, self.piece_x, self.piece_y):
            self.game_over = True

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        return lines_cleared

    def move_sideways(self, direction):
        new_x = self.piece_x + direction
        if self.valid_move(self.current_piece, new_x, self.piece_y):
            self.piece_x = new_x

    def move_down(self):
        new_y = self.piece_y + 1
        if self.valid_move(self.current_piece, self.piece_x, new_y):
            self.piece_y = new_y
        else:
            self.lock_piece()

    def rotate_piece(self):
        rotated_piece = rotate(self.current_piece)
        if self.valid_move(rotated_piece, self.piece_x, self.piece_y):
            self.current_piece = rotated_piece

    def draw(self, screen, offset_x):
        # Draw the grid
        for i in range(GRID_HEIGHT):
            for j in range(GRID_WIDTH):
                if self.grid[i][j]:
                    pygame.draw.rect(screen, COLORS[self.grid[i][j]], (offset_x + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                else:
                    pygame.draw.rect(screen, COLORS[0], (offset_x + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1) #Outline

        # Draw the current piece
        for i in range(len(self.current_piece)):
            for j in range(len(self.current_piece[0])):
                if self.current_piece[i][j]:
                    pygame.draw.rect(screen, COLORS[self.color], (offset_x + (self.piece_x + j) * CELL_SIZE, (self.piece_y + i) * CELL_SIZE, CELL_SIZE, CELL_SIZE))

        # Display score
        font = pygame.font.Font(None, 30)
        text = font.render(f"Player {self.player_id} Score: {self.score}", True, COLORS[7])
        screen.blit(text, (offset_x, GRID_HEIGHT * CELL_SIZE + 10))

# Game Logic
def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Tetris for Three")

    player1 = Tetris(1)
    player2 = Tetris(2)
    player3 = Tetris(3)
    players = [player1, player2, player3]

    clock = pygame.time.Clock()
    fall_speed = 30  # Frames per drop
    fall_counter = 0

    # Finances
    player_balances = {1: 100, 2: 100, 3: 100} # Starting balances
    bet_amount = 10
    total_pot = 0
    contribution = {1: 0, 2: 0, 3: 0}

    def place_bet(player_id):
        nonlocal total_pot
        if player_balances[player_id] >= bet_amount:
            player_balances[player_id] -= bet_amount
            total_pot += bet_amount
            contribution[player_id] += bet_amount
            print(f"Player {player_id} placed a bet of {bet_amount}.  Pot: {total_pot}, Balance: {player_balances[player_id]}")
        else:
            print(f"Player {player_id} does not have enough funds to bet.")

    def distribute_winnings(winning_player_id):
        nonlocal total_pot
        player_balances[winning_player_id] += total_pot
        print(f"Player {winning_player_id} wins the pot of {total_pot}!")
        total_pot = 0
        contribution[1] = 0
        contribution[2] = 0
        contribution[3] = 0

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    player1.move_sideways(-1)
                if event.key == pygame.K_RIGHT:
                    player1.move_sideways(1)
                if event.key == pygame.K_DOWN:
                    player1.move_down()
                if event.key == pygame.K_UP:
                    player1.rotate_piece()

                if event.key == pygame.K_a:
                    player2.move_sideways(-1)
                if event.key == pygame.K_d:
                    player2.move_sideways(1)
                if event.key == pygame.K_s:
                    player2.move_down()
                if event.key == pygame.K_w:
                    player2.rotate_piece()

                if event.key == pygame.K_j:
                    player3.move_sideways(-1)
                if event.key == pygame.K_l:
                    player3.move_sideways(1)
                if event.key == pygame.K_k:
                    player3.move_down()
                if event.key == pygame.K_i:
                    player3.rotate_piece()

                if event.key == pygame.K_1:
                    place_bet(1)
                if event.key == pygame.K_2:
                    place_bet(2)
                if event.key == pygame.K_3:
                    place_bet(3)

                if event.key == pygame.K_SPACE: #Example of distributing winnings (replace with actual win condition)
                    winner = random.choice([1,2,3])
                    distribute_winnings(winner)

        # Game Logic Update
        fall_counter += 1
        for player in players:
            if not player.game_over:
                if fall_counter >= fall_speed:
                    player.move_down()
                    fall_counter = 0

        # Drawing
        screen.fill(COLORS[0])  # Black background
        player1.draw(screen, 0)
        player2.draw(screen, GRID_WIDTH * CELL_SIZE + 20)
        player3.draw(screen, 2 * (GRID_WIDTH * CELL_SIZE + 20))

        # Display balances and pot
        font = pygame.font.Font(None, 30)
        text1 = font.render(f"Player 1 Balance: {player_balances[1]}", True, COLORS[7])
        text2 = font.render(f"Player 2 Balance: {player_balances[2]}", True, COLORS[7])
        text3 = font.render(f"Player 3 Balance: {player_balances[3]}", True, COLORS[7])
        pot_text = font.render(f"Total Pot: {total_pot}", True, COLORS[7])
        contrib1 = font.render(f"Player 1 Contribution: {contribution[1]}", True, COLORS[7])
        contrib2 = font.render(f"Player 2 Contribution: {contribution[2]}", True, COLORS[7])
        contrib3 = font.render(f"Player 3 Contribution: {contribution[3]}", True, COLORS[7])

        screen.blit(text1, (0, HEIGHT - 90))
        screen.blit(text2, (0, HEIGHT - 60))
        screen.blit(text3, (0, HEIGHT - 30))
        screen.blit(pot_text, (300, HEIGHT - 60))
        screen.blit(contrib1, (300, HEIGHT - 90))
