import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = GRID_WIDTH * BLOCK_SIZE * 3  # Three players side-by-side
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
          (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)]  # Black, Red, Green, Blue, Yellow, Magenta, Cyan, White

# Tetromino shapes (7 shapes, each with 4 rotations)
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]]   # T
]

def create_grid(width, height):
    return [[0] * width for _ in range(height)]

def draw_grid(screen, grid, offset_x):
    for y in range(len(grid)):
        for x in range(len(grid[y])):
            if grid[y][x] != 0:
                pygame.draw.rect(screen, COLORS[grid[y][x]],
                                 (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, COLORS[7],
                                 (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1) # White outline
            else:
                pygame.draw.rect(screen, COLORS[0],
                                 (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, COLORS[7],
                                 (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1) # White outline

def new_piece():
    shape = random.choice(SHAPES)
    color = random.randint(1, 6)
    return {'shape': shape, 'color': color, 'x': GRID_WIDTH // 2 - len(shape[0]) // 2, 'y': 0}

def rotate(shape):
    return list(zip(*shape[::-1]))

def is_valid_move(grid, piece, offset_x, offset_y):
    for y, row in enumerate(piece['shape']):
        for x, cell in enumerate(row):
            if cell:
                grid_x = offset_x + piece['x'] + x
                grid_y = offset_y + piece['y'] + y
                if grid_x < 0 or grid_x >= len(grid[0]) or grid_y >= len(grid) or grid[y][grid_x] != 0:
                    return False
    return True

def place_piece(grid, piece, offset_x, offset_y):
    for y, row in enumerate(piece['shape']):
        for x, cell in enumerate(row):
            if cell:
                grid[offset_y + piece['y'] + y][offset_x + piece['x'] + x] = piece['color']

def clear_lines(grid, player_index, scores, contributions):
    lines_cleared = 0
    full_rows = []
    for i, row in enumerate(grid):
        if all(row):
            full_rows.append(i)

    for row_index in full_rows:
        del grid[row_index]
        grid.insert(0, [0] * GRID_WIDTH)
        lines_cleared += 1

    if lines_cleared > 0:
        scores[player_index] += lines_cleared * lines_cleared * 100  # Example scoring
        contributions[player_index] += lines_cleared
    return lines_cleared

def game_over(grid):
    return any(grid[0][i] != 0 for i in range(GRID_WIDTH))

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Collaborative Tetris")
    clock = pygame.time.Clock()

    grids = [create_grid(GRID_WIDTH, GRID_HEIGHT) for _ in range(3)]
    pieces = [new_piece() for _ in range(3)]
    scores = [0, 0, 0]
    contributions = [0, 0, 0]
    game_states = [True, True, True] # True = playing, False = game over
    player_controls = [
        {'left': pygame.K_a, 'right': pygame.K_d, 'rotate': pygame.K_s, 'down': pygame.K_w},
        {'left': pygame.K_j, 'right': pygame.K_l, 'rotate': pygame.K_k, 'down': pygame.K_i},
        {'left': pygame.K_LEFT, 'right': pygame.K_RIGHT, 'rotate': pygame.K_UP, 'down': pygame.K_DOWN}
    ]

    drop_timers = [0, 0, 0]
    drop_speed = 500  # Milliseconds

    font = pygame.font.Font(None, 36)

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                for i in range(3):
                    if game_states[i]:
                        if event.key == player_controls[i]['left']:
                            pieces[i]['x'] -= 1
                            if not is_valid_move(grids[i], pieces[i], i * GRID_WIDTH, 0):
                                pieces[i]['x'] += 1
                        if event.key == player_controls[i]['right']:
                            pieces[i]['x'] += 1
                            if not is_valid_move(grids[i], pieces[i], i * GRID_WIDTH, 0):
                                pieces[i]['x'] -= 1
                        if event.key == player_controls[i]['rotate']:
                            rotated_shape = rotate(pieces[i]['shape'])
                            temp_piece = pieces[i].copy()
                            temp_piece['shape'] = rotated_shape
                            if is_valid_move(grids[i], temp_piece, i * GRID_WIDTH, 0):
                                pieces[i]['shape'] = rotated_shape
                        if event.key == player_controls[i]['down']:
                            pieces[i]['y'] += 1
                            if not is_valid_move(grids[i], pieces[i], i * GRID_WIDTH, 0):
                                pieces[i]['y'] -= 1
                                place_piece(grids[i], pieces[i], i * GRID_WIDTH, 0)
                                clear_lines(grids[i], i, scores, contributions)
                                pieces[i] = new_piece()
                                if game_over(grids[i]):
                                    game_states[i] = False

        screen.fill(COLORS[0])  # Black background

        for i in range(3):
            if game_states[i]:
                drop_timers[i] += clock.get_rawtime()
                clock.tick()

                if drop_timers[i] > drop_speed:
                    drop_timers[i] = 0
                    pieces[i]['y'] += 1
                    if not is_valid_move(grids[i], pieces[i], i * GRID_WIDTH, 0):
                        pieces[i]['y'] -= 1
                        place_piece(grids[i], pieces[i], i * GRID_WIDTH, 0)
                        clear_lines(grids[i], i, scores, contributions)
                        pieces[i] = new_piece()
                        if game_over(grids[i]):
                            game_states[i] = False

            draw_grid(screen, grids[i], i * GRID_WIDTH * BLOCK_SIZE)

            # Draw the current piece
            if game_states[i]:
                for y, row in enumerate(pieces[i]['shape']):
                    for x, cell in enumerate(row):
                        if cell:
                            pygame.draw.rect(screen, COLORS[pieces[i]['color']],
                                             (i * GRID_WIDTH * BLOCK_SIZE + (pieces[i]['x'] + x) * BLOCK_SIZE,
                                              (pieces[i]['y'] + y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                            pygame.draw.rect(screen, COLORS[7],
                                             (i * GRID_WIDTH * BLOCK_SIZE + (pieces[i]['x'] + x) * BLOCK_SIZE,
                                              (pieces[i]['y'] + y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1) # White outline

            # Display score
            score_text = font.render(f"Player {i+1} Score: {scores[i]}", True, COLORS[7])
            screen.blit(score_text, (i * GRID_WIDTH * BLOCK_SIZE, HEIGHT - 40))

            # Display Game Over message
            if not game_states[i]:
                game_over_text = font.render("Game Over!", True, COLORS[1])
                text_rect = game_over_text.get_rect(center=(i * GRID_WIDTH * BLOCK_SIZE + GRID_WIDTH * BLOCK_SIZE // 2, HEIGHT // 2))
                screen.blit(game_over_text, text_rect)

        pygame.display.flip()
        clock.tick(FPS)

    # Determine the winner based on contribution
    if all(not state for state in game_states): # All games are over
        total_contributions = sum(contributions)
        if total_contributions > 0:
            contribution_percentages = [c / total_contributions * 100 for c in contributions]
            print("Contribution Percentages:", contribution_percentages)
            winner_index = contributions.index(max(contributions))
            print(f"Player {winner_index + 1} contributed the most and is the winner!")
        else:
            print("No lines were cleared, so there is no winner.")
    else:
        print("The game was quit before all players lost.")

    pygame.quit()

if __name__ == "__main__":
    main()

