class TetriBoard:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.board = [[' ' for _ in range(width)] for _ in range(height)]

    def is_valid_move(self, piece, x, y):
        for i in range(len(piece.shape)):
            for j in range(len(piece.shape[0])):
                if piece.shape[i][j] != ' ':
                    board_x = x + j
                    board_y = y + i
                    if (board_x < 0 or board_x >= self.width or
                        board_y < 0 or board_y >= self.height or
                        self.board[board_y][board_x] != ' '):
                        return False
        return True

    def place_piece(self, piece, x, y):
        for i in range(len(piece.shape)):
            for j in range(len(piece.shape[0])):
                if piece.shape[i][j] != ' ':
                    self.board[y + i][x + j] = piece.color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(cell != ' ' for cell in self.board[i]):
                del self.board[i]
                self.board.insert(0, [' ' for _ in range(self.width)])
                lines_cleared += 1
        return lines_cleared

    def display(self):
        for row in self.board:
            print('|' + ''.join(row) + '|')
        print('-' * (self.width + 2))

class Player:
    def __init__(self, player_id, color):
        self.player_id = player_id
        self.score = 0
        self.color = color

class TetriGame:
    def __init__(self, width=10, height=20, num_players=3):
        self.board = TetriBoard(width, height)
        self.players = [Player(i, self.get_player_color(i)) for i in range(num_players)]
        self.current_player_index = 0
        self.game_over = False
        self.pieces = self.generate_pieces()
        self.current_piece = self.get_next_piece()
        self.piece_x = width // 2 - 2
        self.piece_y = 0

    def get_player_color(self, player_id):
        colors = ['R', 'G', 'B']  # Red, Green, Blue
        return colors[player_id % len(colors)]

    def generate_pieces(self):
        # Define some Tetris pieces
        pieces = [
            TetriPiece([['X', 'X', 'X', 'X']], 'C'),  # I-piece (Cyan)
            TetriPiece([['X', 'X'], ['X', 'X']], 'Y'),  # O-piece (Yellow)
            TetriPiece([[' ', 'X', 'X'], ['X', 'X', ' ']], 'P'),  # S-piece (Purple)
            TetriPiece([['X', 'X', ' '], [' ', 'X', 'X']], 'O'),  # Z-piece (Orange)
            TetriPiece([['X', ' ', ' '], ['X', 'X', 'X']], 'R'),  # L-piece (Red)
            TetriPiece([[' ', ' ', 'X'], ['X', 'X', 'X']], 'G'),  # J-piece (Green)
            TetriPiece([[' ', 'X', ' '], ['X', 'X', 'X']], 'B')   # T-piece (Blue)
        ]
        return pieces

    def get_next_piece(self):
        return random.choice(self.pieces)

    def move_piece(self, dx):
        if self.board.is_valid_move(self.current_piece, self.piece_x + dx, self.piece_y):
            self.piece_x += dx

    def rotate_piece(self):
        rotated_piece = TetriPiece([row[:] for row in self.current_piece.shape], self.current_piece.color)
        rotated_piece.rotate()
        if self.board.is_valid_move(rotated_piece, self.piece_x, self.piece_y):
            self.current_piece.rotate()

    def drop_piece(self):
        while self.board.is_valid_move(self.current_piece, self.piece_x, self.piece_y + 1):
            self.piece_y += 1
        self.place_piece()

    def place_piece(self):
        self.board.place_piece(self.current_piece, self.piece_x, self.piece_y)
        lines_cleared = self.board.clear_lines()
        self.players[self.current_player_index].score += lines_cleared * lines_cleared * 100  # Example scoring
        self.next_turn()

    def next_turn(self):
        self.current_player_index = (self.current_player_index + 1) % len(self.players)
        self.current_piece = self.get_next_piece()
        self.piece_x = self.board.width // 2 - 2
        self.piece_y = 0
        if not self.board.is_valid_move(self.current_piece, self.piece_x, self.piece_y):
            self.game_over = True

    def display_game(self):
        self.board.display()
        for player in self.players:
            print(f"Player {player.player_id} ({player.color}): Score = {player.score}")
        print(f"Current Player: {self.current_player_index} ({self.players[self.current_player_index].color})")

    def get_player_input(self):
        while True:
            print("Enter command (a=left, d=right, s=drop, r=rotate, q=quit):")
            command = input().lower()
            if command in ['a', 'd', 's', 'r', 'q']:
                return command
            else:
                print("Invalid command. Try again.")

    def play(self):
        while not self.game_over:
            self.display_game()
            command = self.get_player_input()

            if command == 'a':
                self.move_piece(-1)
            elif command == 'd':
                self.move_piece(1)
            elif command == 's':
                self.drop_piece()
            elif command == 'r':
                self.rotate_piece()
            elif command == 'q':
                self.game_over = True
                break

        print("Game Over!")
        self.display_game()
        self.display_final_scores()

    def display_final_scores(self):
        total_score = sum(player.score for player in self.players)
        if total_score == 0:
            print("No one scored any points!")
            return

        print("\nFinal Scores and Contributions:")
        for player in self.players:
            contribution = (player.score / total_score) * 100 if total_score > 0 else 0
            print(f"Player {player.player_id} ({player.color}): Score = {player.score}, Contribution = {contribution:.2f}%")

if __name__ == '__main__':
    game = TetriGame()
    game.play()

