    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[0, 1, 0], [1, 1, 1]],  # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j] == 1:
                    cells.append((self.x + j, self.y + i))
        return cells

class Game:
    def __init__(self, player_names):
        pygame.init()
        self.screen = pygame.display.set_mode((TOTAL_WIDTH, TOTAL_HEIGHT))
        pygame.display.set_caption("Troika Tetris")
        self.clock = pygame.time.Clock()
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.player_names = player_names
        self.player_scores = {name: 0 for name in player_names}
        self.player_colors = {name: COLORS[i+1] for i, name in enumerate(player_names)} # Avoid gray
        self.current_tetromino = self.new_tetromino()
        self.game_over = False
        self.font = pygame.font.Font(None, 30)
        self.player_lots = {name: 0 for name in player_names}
        self.total_lines_cleared = 0
        self.player_lines_cleared = {name: 0 for name in player_names}

    def new_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.choice(COLORS[1:]) # Avoid gray
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= GRID_WIDTH or y >= GRID_HEIGHT or (y >= 0 and self.grid[y][x] != 0):
                return False
        return True

    def lock_tetromino(self):
        for x, y in self.current_tetromino.get_cells():
            if y < 0: # Game over if piece locks above the screen
                self.game_over = True
                return
            self.grid[y][x] = self.current_tetromino.color
        self.clear_lines()
        self.current_tetromino = self.new_tetromino()
        if not self.valid_move(self.current_tetromino):
            self.game_over = True

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y][x] != 0 for x in range(GRID_WIDTH)):
                lines_cleared += 1
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)

        if lines_cleared > 0:
            # Assign line clearing credit randomly to a player
            clearing_player = random.choice(self.player_names)
            self.player_lines_cleared[clearing_player] += lines_cleared
            self.total_lines_cleared += lines_cleared
            self.update_scores(clearing_player, lines_cleared)

    def update_scores(self, player, lines_cleared):
        # Simple scoring system: 100 points per line cleared
        self.player_scores[player] += lines_cleared * 100

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
                pygame.quit()
                sys.exit()
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.current_tetromino.x -= 1
                    if not self.valid_move(self.current_tetromino):
                        self.current_tetromino.x += 1
                elif event.key == pygame.K_RIGHT:
                    self.current_tetromino.x += 1
                    if not self.valid_move(self.current_tetromino):
                        self.current_tetromino.x -= 1
                elif event.key == pygame.K_DOWN:
                    self.current_tetromino.y += 1
                    if not self.valid_move(self.current_tetromino):
                        self.current_tetromino.y -= 1
                        self.lock_tetromino()
                elif event.key == pygame.K_UP:
                    original_shape = self.current_tetromino.shape
                    self.current_tetromino.rotate()
                    if not self.valid_move(self.current_tetromino):
                        self.current_tetromino.shape = original_shape # Revert rotation if invalid
                elif event.key == pygame.K_SPACE:
                    # Hard drop
                    while self.valid_move(self.current_tetromino):
                        self.current_tetromino.y += 1
                    self.current_tetromino.y -= 1
                    self.lock_tetromino()

    def update(self):
        if not self.game_over:
            self.current_tetromino.y += 1
            if not self.valid_move(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.lock_tetromino()

    def draw_grid(self):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = WHITE if self.grid[y][x] == 0 else self.grid[y][x]
                pygame.draw.rect(self.screen, color,
                                 (MARGIN + x * CELL_SIZE, MARGIN + y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                pygame.draw.rect(self.screen, GRAY,
                                 (MARGIN + x * CELL_SIZE, MARGIN + y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_tetromino(self):
        for x, y in self.current_tetromino.get_cells():
            if y >= 0: # Only draw if within the grid
                pygame.draw.rect(self.screen, self.current_tetromino.color,
                                 (MARGIN + x * CELL_SIZE, MARGIN + y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                pygame.draw.rect(self.screen, GRAY,
                                 (MARGIN + x * CELL_SIZE, MARGIN + y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_scores(self):
        y_offset = 20
        for player, score in self.player_scores.items():
            text = self.font.render(f"{player}: {score}", True, self.player_colors[player])
            self.screen.blit(text, (WIDTH + MARGIN + 20, MARGIN + y_offset))
            y_offset += 30

    def draw_lots(self):
        y_offset = 20
        for player, lot in self.player_lots.items():
            text = self.font.render(f"{player} Lot: {lot}", True, self.player_colors[player])
            self.screen.blit(text, (20, MARGIN + HEIGHT + y_offset))
            y_offset += 30

    def draw_game_over(self):
        text = self.font.render("Game Over!", True, RED)
        text_rect = text.get_rect(center=(TOTAL_WIDTH // 2, TOTAL_HEIGHT // 2))
        self.screen.blit(text, text_rect)

    def calculate_contribution(self):
        total_score = sum(self.player_scores.values())
        if total_score == 0:
            return {name: 0 for name in self.player_names}
        else:
            return {name: self.player_scores[name] / total_score for name in self.player_names}

    def draw_contribution(self):
        contributions = self.calculate_contribution()
        y_offset = 20
        for player, contribution in contributions.items():
            text = self.font.render(f"{player} Contribution: {contribution:.2f}", True, self.player_colors[player])
            self.screen.blit(text, (20, MARGIN + y_offset))
            y_offset += 30

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()

            self.screen.fill(BLACK)
            self.draw_grid()
            self.draw_tetromino()
            self.draw_scores()
            self.draw_lots()
            self.draw_contribution()

            if self.game_over:
                self.draw_game_over()

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.time.delay(2000) # Wait 2 seconds before quitting after game over
        pygame.quit()
        sys.exit()

if __name__ == '__main__':
    player_names = ["Alice", "Bob", "Charlie"]
    game = Game(player_names)
    game.run()

